'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { motion, AnimatePresence } from 'motion/react';
import { Search, Filter, Sparkles, BookOpen, Users, ArrowRight, Calendar, User as UserIcon } from 'lucide-react';
import { Input, Button } from 'antd';
import Image from 'next/image';

interface PostItem {
  slug: string;
  title: string;
  date?: string;
  author?: string;
  tags: string[];
  cover?: string;
  description?: string;
}

interface HomePostGridProps {
  posts: PostItem[];
  postCount: number;
  facesCount: number;
  siteTitle: string;
  siteDescription: string;
}

/**
 * 首页帖子网格 — 客户端组件，负责搜索/筛选交互
 */
export function HomePostGrid({ posts, postCount, facesCount, siteTitle, siteDescription }: HomePostGridProps) {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredPosts = posts.filter((p) => {
    if (!searchTerm) return true;
    const q = searchTerm.toLowerCase();
    return (
      p.title.toLowerCase().includes(q) ||
      p.description?.toLowerCase().includes(q) ||
      p.tags?.some((t) => t.toLowerCase().includes(q))
    );
  });

  return (
    <main className="flex-1 max-w-7xl mx-auto w-full px-6 py-12 md:py-20">
      {/* 英雄区域 */}
      <section className="mb-16">
        <motion.div
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          className="flex items-center gap-2 text-zinc-400 font-black text-[10px] uppercase tracking-[0.2em] mb-6"
        >
          <div className="w-1.5 h-1.5 rounded-full bg-zinc-900 animate-pulse"></div>
          <span>Originium Kernel is Online</span>
        </motion.div>

        <motion.h1
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="text-5xl md:text-7xl font-display font-black tracking-tighter text-zinc-900 mb-8 leading-[0.95]"
        >
          Write. Sync. <br />
          <span className="text-zinc-300">Deploy.</span>
        </motion.h1>

        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.2 }}
        >
          <div className="flex gap-3 items-center max-w-2xl">
            <div className="relative flex-1 w-full">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-300 group-focus-within:text-zinc-900 transition-colors" size={20} />
              <Input
                placeholder="搜索内容..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-12 h-14 text-base w-full rounded-2xl bg-white border-zinc-200 hover:border-zinc-300 transition-colors"
                size="large"
                variant="outlined"
              />
            </div>
            <Button size="large" icon={<Filter size={20} />} className="bg-white hover:bg-zinc-50 border-zinc-200 rounded-2xl">
              排序
            </Button>
          </div>
        </motion.div>
      </section>

      {/* 快捷入口 */}
      <section className="mb-12">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Link href="/posts" className="group">
            <div className="bg-white rounded-3xl border border-zinc-100 p-8 hover:border-zinc-300 hover:shadow-lg transition-all duration-300">
              <div className="flex items-center justify-between mb-4">
                <div className="w-12 h-12 bg-zinc-50 rounded-2xl flex items-center justify-center group-hover:bg-zinc-900 group-hover:text-white transition-colors duration-300">
                  <BookOpen size={24} className="text-zinc-400 group-hover:text-white transition-colors" />
                </div>
                <ArrowRight size={20} className="text-zinc-300 group-hover:text-zinc-900 group-hover:translate-x-1 transition-all" />
              </div>
              <h2 className="text-xl font-bold text-zinc-900 mb-1">帖子</h2>
              <p className="text-zinc-400 text-sm">
                {postCount > 0 ? `${postCount} 篇帖子` : '浏览所有帖子'}
              </p>
            </div>
          </Link>
          <Link href="/faces" className="group">
            <div className="bg-white rounded-3xl border border-zinc-100 p-8 hover:border-zinc-300 hover:shadow-lg transition-all duration-300">
              <div className="flex items-center justify-between mb-4">
                <div className="w-12 h-12 bg-zinc-50 rounded-2xl flex items-center justify-center group-hover:bg-zinc-900 group-hover:text-white transition-colors duration-300">
                  <Users size={24} className="text-zinc-400 group-hover:text-white transition-colors" />
                </div>
                <ArrowRight size={20} className="text-zinc-300 group-hover:text-zinc-900 group-hover:translate-x-1 transition-all" />
              </div>
              <h2 className="text-xl font-bold text-zinc-900 mb-1">通讯录</h2>
              <p className="text-zinc-400 text-sm">
                {facesCount > 0 ? `${facesCount} 位联系人` : '浏览通讯录'}
              </p>
            </div>
          </Link>
        </div>
      </section>

      {/* 帖子列表 */}
      <section>
        <div className="flex items-center justify-between mb-8">
          <h2 className="text-2xl font-bold text-zinc-900">最新帖子</h2>
          {posts.length > 0 && (
            <Link href="/posts" className="text-sm text-zinc-400 hover:text-zinc-900 flex items-center gap-1 transition-colors">
              查看全部 <ArrowRight size={14} />
            </Link>
          )}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <AnimatePresence mode="popLayout">
            {filteredPosts.length > 0
              ? filteredPosts.slice(0, 8).map((post) => (
                  <motion.div
                    key={post.slug}
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.95 }}
                    className="group bg-white rounded-[2rem] border-2 border-zinc-50 overflow-hidden hover:border-zinc-900 transition-all duration-500 shadow-sm hover:shadow-2xl hover:shadow-zinc-100 flex flex-col"
                  >
                    <Link href={`/posts${post.slug}`} className="block overflow-hidden aspect-[16/10] bg-zinc-50 relative">
                      {post.cover ? (
                        <Image
                          src={post.cover}
                          alt={post.title}
                          fill
                          className="object-cover group-hover:scale-110 transition-transform duration-700"
                          sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-zinc-100 font-black text-6xl select-none">
                          {post.title.charAt(0)}
                        </div>
                      )}
                      <div className="absolute inset-0 bg-zinc-900/0 group-hover:bg-zinc-900/10 transition-colors duration-500" />
                      <div className="absolute top-6 right-6 w-12 h-12 bg-white rounded-2xl flex items-center justify-center opacity-0 group-hover:opacity-100 translate-y-2 group-hover:translate-y-0 transition-all duration-500 shadow-lg">
                        <ArrowRight size={24} className="text-zinc-900" />
                      </div>
                    </Link>
                    <div className="p-8 flex-1 flex flex-col">
                      <div className="flex flex-wrap gap-2 mb-6">
                        {post.tags.slice(0, 3).map((tag) => (
                          <span key={tag} className="text-[10px] font-black uppercase tracking-widest text-zinc-400 border border-zinc-100 px-2 py-0.5 rounded-full">
                            {tag}
                          </span>
                        ))}
                      </div>
                      <Link href={`/posts${post.slug}`} className="block group/title">
                        <h3 className="text-2xl font-black text-zinc-900 mb-4 line-clamp-2 leading-tight group-hover/title:text-zinc-600 transition-colors">
                          {post.title}
                        </h3>
                      </Link>
                      <p className="text-zinc-400 text-sm line-clamp-2 mb-8 font-medium leading-relaxed">
                        {post.description || ''}
                      </p>
                      <div className="mt-auto pt-8 border-t border-zinc-50 flex items-center justify-between text-zinc-400">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 bg-zinc-50 rounded-xl flex items-center justify-center text-zinc-900 group-hover:bg-zinc-900 group-hover:text-white transition-colors duration-500">
                            <UserIcon size={14} />
                          </div>
                          <span className="text-xs font-bold text-zinc-900 uppercase tracking-tighter">
                            {post.author || '匿名'}
                          </span>
                        </div>
                        {post.date && (
                          <div className="flex items-center gap-2 text-[10px] font-black">
                            <Calendar size={12} />
                            <span>
                              {new Date(post.date).toLocaleDateString('zh-CN', { month: 'short', day: 'numeric' })}
                            </span>
                          </div>
                        )}
                      </div>
                    </div>
                  </motion.div>
                ))
              : (
                  <div className="col-span-full py-32 text-center bg-white rounded-[3rem] border border-zinc-100 shadow-sm">
                    <div className="w-24 h-24 bg-zinc-50 rounded-full flex items-center justify-center mx-auto mb-6 text-zinc-300">
                      <Sparkles size={40} />
                    </div>
                    <h3 className="text-2xl font-black text-zinc-900 mb-2">The kernel is empty</h3>
                    <p className="text-zinc-400 font-medium">
                      在 /posts 目录下添加 Markdown 文件即可发布内容
                    </p>
                  </div>
                )}
          </AnimatePresence>
        </div>
      </section>
    </main>
  );
}

'use client';

import React, { useEffect, useState, Suspense } from 'react';
import { useParams } from 'next/navigation';
import { Navbar } from '@/components/Navbar';
import { MarkdownRenderer } from '@/components/MarkdownRenderer';
import { ArrowLeft, User, Calendar, Tag } from 'lucide-react';
import Link from 'next/link';
import Image from 'next/image';

function UserArticleContent() {
  const params = useParams();
  const username = params?.user as string;
  const article = params?.article as string;

  const [articleData, setArticleData] = useState<any>(null);
  const [userData, setUserData] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchArticle = async () => {
      try {
        const res = await fetch(`/api/u/${username}/${article}`);
        if (res.ok) {
          const data = await res.json();
          setArticleData(data.article);
          setUserData(data.user);
        }
      } catch (error) {
        console.error('Fetch article error:', error);
      } finally {
        setLoading(false);
      }
    };

    if (username && article) fetchArticle();
  }, [username, article]);

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-white">
      <div className="flex flex-col items-center gap-4 animate-pulse">
        <div className="w-12 h-12 bg-zinc-100 rounded-full"></div>
        <div className="h-4 w-32 bg-zinc-100 rounded"></div>
      </div>
    </div>
  );

  if (!articleData) return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <div className="flex-1 flex flex-col items-center justify-center p-6 text-center">
        <h1 className="text-4xl font-display font-black text-zinc-900 mb-4">404</h1>
        <p className="text-zinc-500 mb-8">Article not found in this kernel.</p>
        <Link href="/" className="lobe-button bg-zinc-900 text-white px-8 py-3 rounded-xl">
          Back Home
        </Link>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />

      <main className="flex-1 max-w-4xl mx-auto w-full px-6 py-12 md:py-20">
        <Link href={`/${username}`} className="inline-flex items-center gap-2 text-zinc-400 hover:text-zinc-900 mb-12 transition-all group">
          <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
          <span className="font-medium">Back to {userData?.name}&apos;s Profile</span>
        </Link>

        <article>
          <header className="mb-12">
            <div className="flex flex-wrap gap-2 mb-8">
              {articleData.tags?.map((tag: string) => (
                <span key={tag} className="flex items-center gap-1.5 px-3 py-1 bg-zinc-50 text-zinc-500 text-xs font-bold uppercase tracking-widest rounded-full border border-zinc-100">
                  <Tag size={12} />
                  {tag}
                </span>
              ))}
            </div>

            <h1 className="text-4xl md:text-7xl font-display font-black tracking-tight text-zinc-900 mb-10 leading-[1.05]">
              {articleData.title}
            </h1>

            <div className="flex flex-wrap items-center gap-6 text-zinc-400 border-y border-zinc-100 py-8">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-zinc-900 rounded-2xl flex items-center justify-center text-white">
                  <User size={20} />
                </div>
                <div>
                  <div className="font-black text-zinc-900 leading-none mb-1">{articleData.authorName}</div>
                  <div className="text-[10px] font-bold uppercase tracking-widest text-zinc-400">@{username}</div>
                </div>
              </div>

              <div className="h-8 w-px bg-zinc-100 hidden sm:block"></div>

              <div className="flex items-center gap-2">
                <Calendar size={18} />
                <time className="text-sm font-bold text-zinc-500">
                  {new Date(articleData.createdAt).toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric' })}
                </time>
              </div>
            </div>
          </header>

          {articleData.coverImage && (
            <div className="w-full aspect-[21/9] rounded-[2rem] overflow-hidden bg-zinc-50 mb-16 shadow-2xl shadow-zinc-200 relative">
              <Image
                src={articleData.coverImage}
                alt={articleData.title}
                fill
                className="object-cover hover:scale-105 transition-transform duration-1000"
                sizes="(max-width: 768px) 100vw, (max-width: 1200px) 90vw, 1200px"
                unoptimized
              />
            </div>
          )}

          <div className="max-w-3xl mx-auto">
             <MarkdownRenderer content={articleData.content} />
          </div>
        </article>
      </main>

      <footer className="border-t border-zinc-100 py-12 bg-zinc-50/50">
        <div className="max-w-4xl mx-auto px-6 text-center">
          <p className="text-zinc-400 text-sm font-medium">Published with Originium Kernel</p>
        </div>
      </footer>
    </div>
  );
}

export default function UserArticlePage() {
  return (
    <Suspense fallback={<div className="min-h-screen bg-white" />}>
      <UserArticleContent />
    </Suspense>
  );
}

'use client';

import React, { useEffect, useState, Suspense } from 'react';
import { useParams } from 'next/navigation';
import { Navbar } from '@/components/Navbar';
import { ArticleCard } from '@/components/ArticleCard';
import { User, Calendar, Mail } from 'lucide-react';
import Link from 'next/link';

function UserProfileContent() {
  const params = useParams();
  const username = params?.user as string;

  const [user, setUser] = useState<any>(null);
  const [articles, setArticles] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchUser = async () => {
      try {
        // Find user by username
        const res = await fetch(`/api/users/${username}`);
        if (res.ok) {
          const data = await res.json();
          setUser(data);

          // Fetch user's articles
          const articlesRes = await fetch(`/api/articles?author=${data.uid}`);
          if (articlesRes.ok) {
            const articlesData = await articlesRes.json();
            setArticles(articlesData.filter((a: any) => a.status === 'published'));
          }
        }
      } catch (error) {
        console.error('Fetch user error:', error);
      } finally {
        setLoading(false);
      }
    };

    if (username) fetchUser();
  }, [username]);

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-white">
      <div className="flex flex-col items-center gap-4 animate-pulse">
        <div className="w-16 h-16 bg-zinc-100 rounded-full"></div>
        <div className="h-6 w-48 bg-zinc-100 rounded"></div>
      </div>
    </div>
  );

  if (!user) return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <div className="flex-1 flex flex-col items-center justify-center p-6 text-center">
        <h1 className="text-4xl font-display font-black text-zinc-900 mb-4">404</h1>
        <p className="text-zinc-500 mb-8">User not found in this kernel.</p>
        <Link href="/" className="lobe-button bg-zinc-900 text-white px-8 py-3 rounded-xl">
          Back Home
        </Link>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />

      <main className="flex-1">
        {/* User Profile Header */}
        <div className="bg-zinc-50 border-b border-zinc-100">
          <div className="max-w-4xl mx-auto px-6 py-12">
            <div className="flex flex-col items-center text-center">
              <div className="w-24 h-24 bg-zinc-900 rounded-3xl flex items-center justify-center text-white mb-6 shadow-xl shadow-zinc-200">
                <User size={40} />
              </div>

              <h1 className="text-4xl font-display font-black text-zinc-900 mb-2">
                {user.name}
              </h1>

              <p className="text-zinc-400 font-medium mb-6">@{username}</p>

              <div className="flex flex-wrap justify-center gap-4 text-sm text-zinc-500">
                <div className="flex items-center gap-2">
                  <Calendar size={16} />
                  <span>Joined {new Date(user.createdAt).toLocaleDateString('en-US', { year: 'numeric', month: 'long' })}</span>
                </div>
                {user.email && (
                  <div className="flex items-center gap-2">
                    <Mail size={16} />
                    <span>{user.email}</span>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Articles Grid */}
        <div className="max-w-4xl mx-auto px-6 py-12">
          <h2 className="text-2xl font-display font-bold text-zinc-900 mb-8">
            Articles ({articles.length})
          </h2>

          {articles.length === 0 ? (
            <div className="text-center py-12 text-zinc-400">
              <p className="font-medium">No articles published yet</p>
            </div>
          ) : (
            <div className="grid gap-6 md:grid-cols-2">
              {articles.map((article) => (
                <ArticleCard key={article.id} article={article} />
              ))}
            </div>
          )}
        </div>
      </main>

      <footer className="border-t border-zinc-100 py-12 bg-zinc-50/50">
        <div className="max-w-4xl mx-auto px-6 text-center">
          <p className="text-zinc-400 text-sm font-medium">Powered by Originium Kernel</p>
        </div>
      </footer>
    </div>
  );
}

export default function UserProfilePage() {
  return (
    <Suspense fallback={<div className="min-h-screen bg-white" />}>
      <UserProfileContent />
    </Suspense>
  );
}

