      {/* 背景设置 */}
      <div className="bg-white rounded-2xl border border-zinc-100 p-6 mb-4">
        <h2 className="text-base font-bold text-zinc-900 mb-4 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500" />
          <ImageIcon size={16} />
          {t('config.background')}
