          </div>
        )}
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import nodemailer from 'nodemailer';

/**
 * 发送绑定验证码
 * 验证邮箱是否属于已有的 Originium Kernel 账户
 */
export async function POST(req: NextRequest) {
  try {
    const { email } = await req.json();
    if (!email || !email.includes('@')) {
      return NextResponse.json({ error: '请输入有效的邮箱地址' }, { status: 400 });
    }

    const db = getDb();

    // 检查邮箱是否存在
    const uid = await db.get(`user:email:${email}`);
    if (!uid) {
      return NextResponse.json({ error: '该邮箱未注册 Originium Kernel 账户' }, { status: 404 });
    }

    // 生成 6 位验证码
    const code = String(Math.floor(100000 + Math.random() * 900000));

    // 存储验证码（5 分钟有效）
    await db.set(`bind:code:${email}`, code, 300);

    // 尝试发送邮件
    const smtpHost = process.env.SMTP_HOST;
    const smtpPort = process.env.SMTP_PORT;
    const smtpUser = process.env.SMTP_USER;
    const smtpPass = process.env.SMTP_PASS;

    if (smtpHost && smtpUser && smtpPass) {
      try {
        const transporter = nodemailer.createTransport({
          host: smtpHost,
          port: parseInt(smtpPort || '587'),
          secure: smtpPort === '465',
          auth: { user: smtpUser, pass: smtpPass },
        });

        await transporter.sendMail({
          from: smtpUser,
          to: email,
          subject: 'Originium Kernel - 账户绑定验证码',
          html: `
            <div style="max-width:480px;margin:0 auto;padding:40px 20px;font-family:-apple-system,BlinkMacSystemFont,sans-serif">
              <h1 style="color:#18181b;font-size:24px;margin-bottom:8px">账户绑定验证</h1>
              <p style="color:#71717a;font-size:14px;margin-bottom:24px">你正在将 Clerk 账户绑定到 Originium Kernel 账户。请输入以下验证码完成绑定：</p>
              <div style="background:#f4f4f5;border-radius:12px;padding:24px;text-align:center;margin-bottom:24px">
                <span style="font-size:36px;font-weight:800;letter-spacing:0.3em;color:#18181b;font-family:monospace">${code}</span>
              </div>
              <p style="color:#a1a1aa;font-size:12px">验证码 5 分钟内有效。如非本人操作，请忽略此邮件。</p>
            </div>
          `,
        });
      } catch (mailErr) {
        console.error('SMTP 发送失败:', mailErr);
        // SMTP 失败不阻塞流程，开发环境可查看日志
        if (process.env.NODE_ENV === 'development') {
          console.log(`[DEV] 验证码: ${code} → ${email}`);
        }
      }
    } else {
      // 未配置 SMTP，开发环境打印验证码
      if (process.env.NODE_ENV === 'development') {
        console.log(`[DEV] 验证码: ${code} → ${email}`);
      } else {
        return NextResponse.json({ error: '邮件服务未配置' }, { status: 500 });
      }
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Bind send code error:', error);
    return NextResponse.json({ error: '发送失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import { createSession } from '@/lib/auth';

function hashPassword(password: string) {
  return Buffer.from(password).toString('hex').split('').reverse().join('');
}

export async function POST(req: NextRequest) {
  try {
    const { login, password } = await req.json();

    if (!login || !password) {
      return NextResponse.json({ error: '缺少登录信息或密码' }, { status: 400 });
    }

    const db = getDb();

    // 支持邮箱或用户名登录
    let uid: string | null = null;

    // 先尝试作为邮箱查找
    if (login.includes('@')) {
      uid = await db.get(`user:email:${login}`);
    }

    // 如果没找到，尝试作为用户名查找
    if (!uid) {
      uid = await db.get(`user:username:${login}`);
    }

    if (!uid) {
      return NextResponse.json({ error: '账号或密码错误' }, { status: 401 });
    }

    const userStr = await db.get(`user:uid:${uid}`);
    if (!userStr) {
      return NextResponse.json({ error: '用户数据异常' }, { status: 500 });
    }

    const user = JSON.parse(userStr);
    const hashedPassword = hashPassword(password);
    if (user.password !== hashedPassword) {
      return NextResponse.json({ error: '账号或密码错误' }, { status: 401 });
    }

    await createSession({
      uid: user.uid,
      email: user.email,
      role: user.role as 'user' | 'admin' | 'sudo',
      userGroup: user.userGroup,
    });

    return NextResponse.json({
      success: true,
      user: {
        uid: user.uid,
        email: user.email,
        username: user.username,
        name: user.name,
        role: user.role
      }
    });
  } catch (error: any) {
    console.error(JSON.stringify({ type: 'login_error', message: error.message }));
    return NextResponse.json({ error: '登录失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import { generateUID, createSession } from '@/lib/auth';
import { loadConfigAsync } from '@/lib/config';

function hashPassword(password: string) {
  return Buffer.from(password).toString('hex').split('').reverse().join('');
}

export async function POST(req: NextRequest) {
  try {
    // 检查是否允许注册
    const config = await loadConfigAsync();
    if (!config.auth.allowRegistration) {
      return NextResponse.json(
        { error: '管理员已关闭注册', errorKey: 'registration_closed' },
        { status: 403 }
      );
    }

    const { email, password, name, username, userGroup } = await req.json();

    if (!email || !password || !name) {
      return NextResponse.json({ error: '缺少必填字段' }, { status: 400 });
    }

    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      return NextResponse.json({ error: '邮箱格式无效' }, { status: 400 });
    }

    if (password.length < 6) {
      return NextResponse.json({ error: '密码至少6个字符' }, { status: 400 });
    }

    if (username) {
      if (!/^[a-zA-Z0-9_]{3,20}$/.test(username)) {
        return NextResponse.json({ error: '用户名只能包含字母、数字和下划线，3-20个字符' }, { status: 400 });
      }
    }

    const db = getDb();

    // 检查是否是第一个用户
    const userListStr = await db.get('users:all:list');
    const isFirstUser = !userListStr || JSON.parse(userListStr).length === 0;

    // 检查邮箱是否已注册
    const existingEmail = await db.get(`user:email:${email}`);
    if (existingEmail) {
      return NextResponse.json({ error: '该邮箱已注册' }, { status: 409 });
    }

    // 检查用户名是否已使用
    if (username) {
      const existingUsername = await db.get(`user:username:${username}`);
      if (existingUsername) {
        return NextResponse.json({ error: '该用户名已被使用' }, { status: 409 });
      }
    }

    const uid = generateUID();

    // 第一个用户自动成为 sudo
    const userRole = isFirstUser ? 'sudo' : 'user';
    const finalUserGroup = isFirstUser ? 'admin' : (userGroup || null);

    // 非第一个用户不能选择管理员组
    if (!isFirstUser && finalUserGroup === 'admin') {
      return NextResponse.json({ error: '无法选择管理员用户组' }, { status: 403 });
    }

    // 存储用户数据
    const hashedPassword = hashPassword(password);
    const userPayload = {
      uid,
      email,
      username: username || null,
      name,
      role: userRole,
      userGroup: finalUserGroup,
      password: hashedPassword,
      createdAt: new Date().toISOString(),
      status: 'active',
    };

    await db.set(`user:uid:${uid}`, JSON.stringify(userPayload));
    await db.set(`user:email:${email}`, uid);

    // 存储用户名映射
    if (username) {
      await db.set(`user:username:${username}`, uid);
    }

    // 更新用户列表
    const userList = userListStr ? JSON.parse(userListStr) : [];
    userList.push(uid);
    await db.set('users:all:list', JSON.stringify(userList));

    await createSession({ uid, email, role: userRole as 'sudo' | 'user' | 'admin' });

    return NextResponse.json({
      success: true,
      user: { uid, email, username, name, role: userRole, userGroup: finalUserGroup },
      message: isFirstUser ? '注册成功！您是首个用户，已获得管理员权限。' : '注册成功！'
    });
  } catch (error: any) {
    console.error(JSON.stringify({ type: 'register_error', message: error.message }));
    return NextResponse.json({ error: error.message || '注册失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import { sendMail, generateResetEmailHtml, isSmtpConfigured } from '@/lib/mail';
import { randomBytes } from 'crypto';

function hashPassword(password: string) {
  return Buffer.from(password).toString('hex').split('').reverse().join('');
}

export async function POST(req: NextRequest) {
  try {
    const { email } = await req.json();

    if (!email) {
      return NextResponse.json({ error: '请输入邮箱' }, { status: 400 });
    }

    if (!isSmtpConfigured()) {
      return NextResponse.json({ error: '邮件服务未配置' }, { status: 500 });
    }

    const db = getDb();
    const uid = await db.get(`user:email:${email}`);

    if (!uid) {
      return NextResponse.json({ success: true, message: '如果邮箱存在，重置链接已发送' }, { status: 201 });
    }

    const token = randomBytes(32).toString('hex');
    const expiresAt = Date.now() + 3600000;

    await db.set(`reset:${token}`, JSON.stringify({ uid, email, expiresAt }), 3600);

    const appUrl = process.env.APP_URL || 'http://localhost:3000';
    const resetLink = `${appUrl}/reset-password?token=${token}`;

    const sent = await sendMail({
      to: email,
      subject: 'Originium Kernel - 密码重置',
      html: generateResetEmailHtml(resetLink),
    });

    if (!sent) {
      return NextResponse.json({ error: '发送邮件失败' }, { status: 500 });
    }

    return NextResponse.json({ success: true, message: '重置链接已发送' }, { status: 201 });
  } catch (error: any) {
    console.error('密码重置错误:', error);
    return NextResponse.json({ error: '服务器错误' }, { status: 500 });
  }
}

export async function PUT(req: NextRequest) {
  try {
    const { token, password } = await req.json();

    if (!token || !password) {
      return NextResponse.json({ error: '缺少必要参数' }, { status: 400 });
    }

    if (password.length < 6) {
      return NextResponse.json({ error: '密码至少6位' }, { status: 400 });
    }

    const db = getDb();
    const resetData = await db.get(`reset:${token}`);

    if (!resetData) {
      return NextResponse.json({ error: '无效或过期的重置链接' }, { status: 400 });
    }

    const { uid, expiresAt } = JSON.parse(resetData);

    if (Date.now() > expiresAt) {
      await db.del(`reset:${token}`);
      return NextResponse.json({ error: '重置链接已过期' }, { status: 400 });
    }

    const userStr = await db.get(`user:uid:${uid}`);
    if (!userStr) {
      return NextResponse.json({ error: '用户不存在' }, { status: 404 });
    }

    const user = JSON.parse(userStr);
    user.password = hashPassword(password);

    await db.set(`user:uid:${uid}`, JSON.stringify(user));
    await db.del(`reset:${token}`);

    return NextResponse.json({ success: true, message: '密码重置成功' }, { status: 201 });
  } catch (error: any) {
    console.error('密码重置错误:', error);
    return NextResponse.json({ error: '服务器错误' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb, storage } from '@/lib/db';
import { getSession } from '@/lib/auth';

/**
 * Cleanup Cron Job API
 * Automatically deletes articles that have been in pending_deletion status for more than 30 days
 * 
 * This should be called periodically (e.g., daily) by a cron scheduler
 */

const DELETION_PERIOD_DAYS = 30;

export async function POST(req: NextRequest) {
  try {
    // Check for admin/sudo or cron secret
    const session = await getSession();
    const cronSecret = req.headers.get('x-cron-secret');
    const expectedSecret = process.env.CRON_SECRET;

    const isAuthorized = 
      (session && (session.role === 'admin' || session.role === 'sudo')) ||
      (cronSecret && expectedSecret && cronSecret === expectedSecret);

    if (!isAuthorized) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const db = getDb();
    const index = await db.hgetall('articles:index');

    const now = Date.now();
    const periodMs = DELETION_PERIOD_DAYS * 24 * 60 * 60 * 1000;

    const deleted: string[] = [];
    const errors: string[] = [];

    for (const [id, data] of Object.entries(index)) {
      try {
        const article = JSON.parse(data);

        if (article.status === 'pending_deletion' && article.deletionRequestedAt) {
          const requestedAt = new Date(article.deletionRequestedAt).getTime();

          // Check if deletion period has expired
          if (now > requestedAt + periodMs) {
            // Permanently delete
            await db.del(`article:data:${id}`);
            await db.hdel('articles:index', id);
            await db.del(`file:articles/${id}.md`);
            deleted.push(id);
          }
        }
      } catch (error: any) {
        errors.push(`Error processing article ${id}: ${error.message}`);
      }
    }

    return NextResponse.json({
      success: true,
      message: `Cleanup completed. Deleted ${deleted.length} articles.`,
      deleted,
      errors,
      timestamp: new Date().toISOString(),
    });
  } catch (error: any) {
    console.error('Cleanup cron error:', error);
    return NextResponse.json({ 
      error: 'Internal server error', 
      details: error.message 
    }, { status: 500 });
  }
}

/**
 * Get cleanup statistics
 */
export async function GET() {
  try {
    const session = await getSession();
    if (!session || (session.role !== 'admin' && session.role !== 'sudo')) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const db = getDb();
    const index = await db.hgetall('articles:index');

    const now = Date.now();
    const periodMs = DELETION_PERIOD_DAYS * 24 * 60 * 60 * 1000;

    let pendingDeletion = 0;
    let expiringSoon = 0; // Within 7 days
    let expired = 0;

    for (const [, data] of Object.entries(index)) {
      const article = JSON.parse(data);

      if (article.status === 'pending_deletion' && article.deletionRequestedAt) {
        pendingDeletion++;

        const requestedAt = new Date(article.deletionRequestedAt).getTime();
        const expiresAt = requestedAt + periodMs;
        const daysRemaining = (expiresAt - now) / (24 * 60 * 60 * 1000);

        if (daysRemaining <= 0) {
          expired++;
        } else if (daysRemaining <= 7) {
          expiringSoon++;
        }
      }
    }

    return NextResponse.json({
      pendingDeletion,
      expiringSoon,
      expired,
      deletionPeriodDays: DELETION_PERIOD_DAYS,
    });
  } catch (error: any) {
    console.error('Cleanup stats error:', error);
    return NextResponse.json({ 
      error: 'Internal server error', 
      details: error.message 
    }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSession } from '@/lib/auth';
import { loadConfigAsync, saveConfigToDb, hasDatabase } from '@/lib/config';
import type { AppConfig } from '@/lib/config';
import { getFileFromGithub, syncConfigToGithub } from '@/lib/github';
import yaml from 'js-yaml';

/**
 * System Configuration API
 *
 * 配置优先级：
 * 1. 数据库缓存（管理员通过此 API 修改的配置）
 * 2. GitHub config.yaml（远程同步配置）
 * 3. config.json（本地文件配置）
 * 4. 默认值
 *
 * 所有配置统一使用 AppConfig 结构
 */
export async function GET() {
  const config = await loadConfigAsync();
  return NextResponse.json(config);
}

export async function POST(req: NextRequest) {
  const session = await getSession();
  if (!session || (session.role !== 'admin' && session.role !== 'sudo')) {
    return NextResponse.json({ error: '无权限' }, { status: 403 });
  }

  try {
    const newConfig = await req.json() as Partial<AppConfig>;
    const currentConfig = await loadConfigAsync();

    // 合并配置，保留未修改的字段
    const mergedConfig: AppConfig = {
      site: {
        title: newConfig.site?.title ?? currentConfig.site.title,
        description: newConfig.site?.description ?? currentConfig.site.description,
        lang: newConfig.site?.lang ?? currentConfig.site.lang,
      },
      appearance: {
        background: newConfig.appearance?.background
          ? { ...currentConfig.appearance.background, ...newConfig.appearance.background }
          : currentConfig.appearance.background,
        customCSS: newConfig.appearance?.customCSS ?? currentConfig.appearance.customCSS,
        customHead: newConfig.appearance?.customHead ?? currentConfig.appearance.customHead,
      },
      access: newConfig.access
        ? {
          posts: { ...currentConfig.access.posts, ...newConfig.access.posts },
          faces: { ...currentConfig.access.faces, ...newConfig.access.faces },
        }
        : currentConfig.access,
      auth: newConfig.auth
        ? { ...currentConfig.auth, ...newConfig.auth }
        : currentConfig.auth,
    };

    // 保存到数据库
    await saveConfigToDb(mergedConfig);

    // 如果有 GitHub 配置，同步站点配置到 GitHub
    const githubRepo = process.env.GITHUB_REPO;
    const githubToken = process.env.GITHUB_TOKEN;
    if (githubRepo && githubToken) {
      const yamlConfig = {
        siteTitle: mergedConfig.site.title,
        siteDescription: mergedConfig.site.description,
      };
      await syncConfigToGithub(githubRepo, githubToken, yamlConfig);
    }

    return NextResponse.json({ success: true, config: mergedConfig });
  } catch (error: any) {
    console.error('更新配置失败:', error);
    return NextResponse.json({ error: error.message || '保存失败' }, { status: 500 });
  }
}

/**
 * 强制从 GitHub 同步配置
 */
export async function PUT() {
  const db = hasDatabase();
  if (!db) {
    return NextResponse.json({ error: '数据库未配置' }, { status: 400 });
  }
  const repo = process.env.GITHUB_REPO;
  const token = process.env.GITHUB_TOKEN;
  if (!repo || !token) {
    return NextResponse.json({ error: 'GitHub 未配置' }, { status: 400 });
  }

  try {
    const remote = await getFileFromGithub(repo, token, 'config.yaml');
    if (!remote) {
      return NextResponse.json({ error: 'config.yaml 不存在' }, { status: 404 });
    }
    const parsed = yaml.load(remote.content) as any;
    const currentConfig = await loadConfigAsync();

    // 从 GitHub YAML 合并到当前配置
    const mergedConfig: AppConfig = {
      site: {
        title: parsed.siteTitle ?? currentConfig.site.title,
        description: parsed.siteDescription ?? currentConfig.site.description,
        lang: currentConfig.site.lang,
      },
      appearance: {
        background: parsed.background
          ? { ...currentConfig.appearance.background, ...parsed.background }
          : currentConfig.appearance.background,
        customCSS: parsed.customCSS ?? currentConfig.appearance.customCSS,
        customHead: parsed.customHead ?? currentConfig.appearance.customHead,
      },
      access: parsed.access
        ? {
          posts: { ...currentConfig.access.posts, ...parsed.access.posts },
          faces: { ...currentConfig.access.faces, ...parsed.access.faces },
        }
        : currentConfig.access,
      auth: parsed.auth
        ? { ...currentConfig.auth, ...parsed.auth }
        : currentConfig.auth,
    };

    await saveConfigToDb(mergedConfig);
    return NextResponse.json({ success: true, config: mergedConfig });
  } catch (error) {
    console.error('从 GitHub 同步配置失败:', error);
    return NextResponse.json({ error: '同步失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getContentFiles, getContentIndexes } from '@/lib/content';
import { loadConfigAsync, canAccess, hasDatabase } from '@/lib/config';
import { getSession, SessionPayload } from '@/lib/auth';
import { getEnvConfig } from '@/lib/env';

/**
 * 通讯录列表 API
 * 根据认证状态和数据库可用性返回可访问的通讯录条目
 */
export async function GET(req: NextRequest) {
  const config = await loadConfigAsync();
  const session = await getSession();
  const isAuthenticated = !!session;
  const dbAvailable = hasDatabase();
  const allFiles = getContentFiles('faces');
  const indexes = getContentIndexes('faces');

  const accessibleFiles = allFiles.filter((file) => {
    const dirSlug = '/' + file.slug.split('/').filter(Boolean).slice(0, -1).join('/');
    return canAccess('faces', file.slug, isAuthenticated, dbAvailable, config) &&
      canAccess('faces', dirSlug || '/', isAuthenticated, dbAvailable, config);
  });

  const accessibleIndexes = indexes.filter((idx) => {
    return canAccess('faces', idx.slug, isAuthenticated, dbAvailable, config);
  });

  return NextResponse.json({
    faces: accessibleFiles.map((f) => ({
      slug: f.slug,
      title: f.meta.title,
      date: f.meta.date,
      tags: f.meta.tags,
      description: f.meta.description,
    })),
    indexes: accessibleIndexes.map((idx) => ({
      slug: idx.slug,
      title: idx.title,
      description: idx.description,
      public: idx.public,
      groupName: idx.groupName,
    })),
    site: config.site,
  });
}

/**
 * 检查用户是否有权限管理指定联系人
 */
function canManageFace(session: SessionPayload | null, faceEmail: string, faceSlug: string): boolean {
  if (!session) return false;
  if (session.role === 'admin' || session.role === 'sudo') return true;
  if (faceEmail && session.email === faceEmail) return true;
  return false;
}

/**
 * 生成文件 slug（从姓名生成）
 */
function generateSlug(name: string): string {
  // 简单处理：移除特殊字符，保留中文、字母、数字，用连字符替换空格
  return name.replace(/[^\u4e00-\u9fa5a-zA-Z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '') || name;
}

/**
 * 从 GitHub 读取文件内容和元数据
 */
async function getFileFromGitHub(req: NextRequest, filePath: string): Promise<{ sha: string; email: string; raw: string } | null> {
  const url = new URL(req.nextUrl.origin + '/api/github');
  url.searchParams.set('path', filePath);

  const response = await fetch(url.toString(), {
    headers: { 'Cookie': req.headers.get('cookie') || '' },
  });

  if (!response.ok) {
    if (response.status === 404) return null;
    throw new Error('读取文件失败');
  }

  const data = await response.json();
  return {
    sha: data.sha,
    email: data.frontMatter?.email || '',
    raw: data.raw,
  };
}

/**
 * 创建联系人
 */
export async function POST(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const { name, email, phone, group, content } = await req.json();

    if (!name || !group) {
      return NextResponse.json({ error: '姓名和分组为必填项' }, { status: 400 });
    }

    const slug = generateSlug(name);
    const filePath = `faces/${group}/${slug}.md`;
    const now = new Date().toISOString();

    const frontMatter = {
      title: name,
      name,
      email: email || '',
      phone: phone || '',
      group,
      date: now,
    };

    const message = `feat: add contact "${name}"`;

    const ghResponse = await fetch(`${req.nextUrl.origin}/api/github`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'create',
        path: filePath,
        frontMatter,
        body: content || '',
        message,
      }),
    });

    if (!ghResponse.ok) {
      const error = await ghResponse.json();
      return NextResponse.json({ error: error.error || '创建联系人失败' }, { status: 500 });
    }

    return NextResponse.json({ success: true, slug: `/${group}/${slug}` });
  } catch (error: any) {
    console.error('create_face_error:', error.message);
    return NextResponse.json({ error: '创建联系人失败' }, { status: 500 });
  }
}

/**
 * 更新联系人
 */
export async function PATCH(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const { slug, name, email, phone, group, content } = await req.json();

    if (!slug) {
      return NextResponse.json({ error: '缺少联系人路径' }, { status: 400 });
    }

    if (!name || !group) {
      return NextResponse.json({ error: '姓名和分组为必填项' }, { status: 400 });
    }

    const oldFilePath = `faces${slug}.md`;

    // 使用统一的 /api/github 端点读取文件
    const fileData = await getFileFromGitHub(req, oldFilePath);
    if (!fileData) {
      return NextResponse.json({ error: '联系人不存在' }, { status: 404 });
    }

    const { sha, email: oldEmail } = fileData;

    if (!canManageFace(session, oldEmail, slug)) {
      return NextResponse.json({ error: '无权修改此联系人' }, { status: 403 });
    }

    const newSlug = generateSlug(name);
    const newFilePath = `faces/${group}/${newSlug}.md`;
    const now = new Date().toISOString();

    const frontMatter = {
      title: name,
      name,
      email: email || '',
      phone: phone || '',
      group,
      date: now,
    };

    if (newFilePath !== oldFilePath) {
      // 创建新文件
      const ghCreateResponse = await fetch(`${req.nextUrl.origin}/api/github`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'create',
          path: newFilePath,
          frontMatter,
          body: content || '',
          message: `update: move contact "${name}" to ${newFilePath}`,
        }),
      });

      if (!ghCreateResponse.ok) {
        const error = await ghCreateResponse.json();
        return NextResponse.json({ error: error.error || '更新联系人失败' }, { status: 500 });
      }

      // 删除旧文件
      const ghDeleteResponse = await fetch(`${req.nextUrl.origin}/api/github`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'delete',
          path: oldFilePath,
          message: `delete: remove old file ${oldFilePath}`,
          sha,
        }),
      });

      if (!ghDeleteResponse.ok) {
        console.error('delete_old_file_error');
      }

      return NextResponse.json({ success: true, slug: `/${group}/${newSlug}` });
    }

    // 更新同一文件
    const ghResponse = await fetch(`${req.nextUrl.origin}/api/github`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'update',
        path: oldFilePath,
        frontMatter,
        body: content || '',
        message: `update: update contact "${name}"`,
        sha,
      }),
    });

    if (!ghResponse.ok) {
      const error = await ghResponse.json();
      return NextResponse.json({ error: error.error || '更新联系人失败' }, { status: 500 });
    }

    return NextResponse.json({ success: true, slug: `/${group}/${newSlug}` });
  } catch (error: any) {
    console.error('update_face_error:', error.message);
    return NextResponse.json({ error: '更新联系人失败' }, { status: 500 });
  }
}

/**
 * 删除联系人
 */
export async function DELETE(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const { slug } = await req.json();

    if (!slug) {
      return NextResponse.json({ error: '缺少联系人路径' }, { status: 400 });
    }

    const filePath = `faces${slug}.md`;

    // 使用统一的 /api/github 端点读取文件
    const fileData = await getFileFromGitHub(req, filePath);
    if (!fileData) {
      return NextResponse.json({ error: '联系人不存在' }, { status: 404 });
    }

    const { sha, email: faceEmail } = fileData;

    if (!canManageFace(session, faceEmail, slug)) {
      return NextResponse.json({ error: '无权删除此联系人' }, { status: 403 });
    }

    const ghResponse = await fetch(`${req.nextUrl.origin}/api/github`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'delete',
        path: filePath,
        message: `delete: delete contact ${slug}`,
        sha,
      }),
    });

    if (!ghResponse.ok) {
      const error = await ghResponse.json();
      return NextResponse.json({ error: error.error || '删除联系人失败' }, { status: 500 });
    }

    return NextResponse.json({ success: true });
  } catch (error: any) {
    console.error('delete_face_error:', error.message);
    return NextResponse.json({ error: '删除联系人失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSession } from '@/lib/auth';
import { getEnvConfig } from '@/lib/env';
import { Octokit } from 'octokit';

/**
 * 统一 GitHub 操作端点
 * POST: 创建/更新/删除文件
 * GET: 读取文件
 */

export async function POST(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const { action, path, content, message, frontMatter, body } = await req.json();

    if (!action || !path) {
      return NextResponse.json({ error: '缺少必需参数' }, { status: 400 });
    }

    const env = getEnvConfig();
    if (!env.githubRepo || !env.githubToken) {
      return NextResponse.json({ error: 'GitHub 配置缺失' }, { status: 500 });
    }

    const [owner, repo] = env.githubRepo.split('/');
    const octokit = new Octokit({ auth: env.githubToken });

    // 获取 SHA（用于更新/删除）
    let sha: string | undefined;
    if (action !== 'create') {
      try {
        const { data } = await octokit.rest.repos.getContent({ owner, repo, path });
        if ('sha' in data) sha = data.sha;
      } catch (e: any) {
        if (e.status !== 404) throw e;
      }
    }

    // 构建文件内容
    let fileContent = content || '';
    if (frontMatter && body !== undefined) {
      const yaml = require('js-yaml');
      fileContent = `---\n${yaml.dump(frontMatter)}---\n\n${body}`;
    }

    if (action === 'delete') {
      if (!sha) return NextResponse.json({ error: '文件不存在' }, { status: 404 });
      const result = await octokit.rest.repos.deleteFile({
        owner, repo, path,
        message: message || `delete: ${path}`,
        sha,
      });
      return NextResponse.json({ success: true, data: result.data });
    }

    // create or update
    const result = await octokit.rest.repos.createOrUpdateFileContents({
      owner, repo, path,
      message: message || `${action}: ${path}`,
      content: Buffer.from(fileContent).toString('base64'),
      sha,
    });

    return NextResponse.json({ success: true, data: result.data });
  } catch (error: any) {
    console.error('github_sync_error:', error.message);
    return NextResponse.json({ error: '操作失败' }, { status: 500 });
  }
}

export async function GET(req: NextRequest) {
  const session = await getSession();
  if (!session) return NextResponse.json({ error: '未登录' }, { status: 401 });

  const path = new URL(req.url).searchParams.get('path');
  if (!path) return NextResponse.json({ error: '缺少路径' }, { status: 400 });

  try {
    const env = getEnvConfig();
    if (!env.githubRepo || !env.githubToken) {
      return NextResponse.json({ error: 'GitHub 配置缺失' }, { status: 500 });
    }

    const [owner, repo] = env.githubRepo.split('/');
    const octokit = new Octokit({ auth: env.githubToken });

    const { data } = await octokit.rest.repos.getContent({ owner, repo, path });

    // Handle directory listing
    if (Array.isArray(data)) {
      return NextResponse.json(data.map(file => ({
        name: file.name,
        path: file.path,
        type: file.type,
        sha: file.sha,
      })));
    }

    // Handle file content
    if ('content' in data) {
      const raw = Buffer.from(data.content, 'base64').toString('utf-8');
      const matter = require('gray-matter');
      const { data: frontMatter, content: body } = matter(raw);

      return NextResponse.json({ raw, frontMatter, body, sha: data.sha });
    }

    return NextResponse.json({ error: '无效路径' }, { status: 400 });
  } catch (error: any) {
    if (error.status === 404) return NextResponse.json({ error: '文件不存在' }, { status: 404 });
    console.error('github_read_error:', error.message);
    return NextResponse.json({ error: '读取失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import { getSession, requireAdmin } from '@/lib/auth';

/**
 * Recycle Bin API
 * - GET: List all articles pending deletion
 * - POST: Restore an article
 * - DELETE: Permanently delete an article
 */

const DELETION_PERIOD_DAYS = 30;

export async function GET(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const db = getDb();
    const index = await db.hgetall('articles:index');

    const pendingDeletion: any[] = [];
    const allArticles: any[] = [];

    for (const [id, data] of Object.entries(index)) {
      const article = JSON.parse(data);
      if (session.role === 'sudo' || session.role === 'admin') {
        allArticles.push({ id, ...article });
        if (article.status === 'pending_deletion') {
          pendingDeletion.push({ id, ...article });
        }
      } else if (article.authorId === session.uid && article.status === 'pending_deletion') {
        pendingDeletion.push({ id, ...article });
      }
    }

    // Calculate days remaining for deletion
    const now = Date.now();
    const periodMs = DELETION_PERIOD_DAYS * 24 * 60 * 60 * 1000;

    const enrichedPending = pendingDeletion.map(article => {
      const requestedAt = new Date(article.deletionRequestedAt).getTime();
      const expiresAt = requestedAt + periodMs;
      const daysRemaining = Math.max(0, Math.ceil((expiresAt - now) / (24 * 60 * 60 * 1000)));
      const canRestore = daysRemaining > 0;

      return {
        ...article,
        daysRemaining,
        expiresAt: new Date(expiresAt).toISOString(),
        canRestore,
      };
    });

    if (req.nextUrl.searchParams.get('all') === 'true' && (session.role === 'admin' || session.role === 'sudo')) {
      return NextResponse.json(allArticles);
    }

    return NextResponse.json(enrichedPending);
  } catch (error) {
    console.error('Recycle bin GET error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

/**
 * Restore an article from recycle bin
 */
export async function POST(req: NextRequest) {
  const session = await requireAdmin(req);
  if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  try {
    const { id } = await req.json();
    if (!id) {
      return NextResponse.json({ error: 'Article ID required' }, { status: 400 });
    }

    const db = getDb();
    const articleStr = await db.get(`article:data:${id}`);
    if (!articleStr) {
      return NextResponse.json({ error: 'Article not found' }, { status: 404 });
    }

    const article = JSON.parse(articleStr);
    if (article.status !== 'pending_deletion') {
      return NextResponse.json({ error: 'Article is not in recycle bin' }, { status: 400 });
    }

    // Check if still within restoration period
    const now = Date.now();
    const requestedAt = new Date(article.deletionRequestedAt).getTime();
    const periodMs = DELETION_PERIOD_DAYS * 24 * 60 * 60 * 1000;

    if (now > requestedAt + periodMs) {
      return NextResponse.json({ error: 'Restoration period expired' }, { status: 400 });
    }

    // Restore article
    const restored = {
      ...article,
      status: 'draft',
      deletionRequestedAt: undefined,
      updatedAt: new Date().toISOString(),
    };

    await db.set(`article:data:${id}`, JSON.stringify(restored));
    await db.hset('articles:index', id, JSON.stringify(restored));

    return NextResponse.json({ success: true, message: 'Article restored' });
  } catch (error) {
    console.error('Restore article error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

/**
 * Permanently delete an article from recycle bin
 */
export async function DELETE(req: NextRequest) {
  const session = await getSession();
  if (!session || (session.role !== 'admin' && session.role !== 'sudo')) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const { id } = await req.json();
    if (!id) {
      return NextResponse.json({ error: 'Article ID required' }, { status: 400 });
    }

    const db = getDb();
    const articleStr = await db.get(`article:data:${id}`);
    if (!articleStr) {
      return NextResponse.json({ error: 'Article not found' }, { status: 404 });
    }

    const article = JSON.parse(articleStr);

    // Only delete if in pending_deletion status or user is sudo
    if (article.status !== 'pending_deletion' && session.role !== 'sudo') {
      return NextResponse.json({ error: 'Cannot delete this article' }, { status: 400 });
    }

    // Permanently delete
    await db.del(`article:data:${id}`);
    await db.hdel('articles:index', id);
    await db.del(`file:articles/${id}.md`);

    return NextResponse.json({ success: true, message: 'Permanently deleted' });
  } catch (error) {
    console.error('Permanent delete error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getTicketTemplates } from '@/lib/tickets';
import { getSession } from '@/lib/auth';
import yaml from 'js-yaml';

/**
 * 工单模板 API
 * - 模板来自 /tickets 目录的 markdown 文件
 * - GET: 从文件系统读取
 * - POST: 创建新模板（admin/sudo）
 */

// 获取所有模板
export async function GET() {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const templates = getTicketTemplates();
    return NextResponse.json(templates);
  } catch (error) {
    console.error(JSON.stringify({ type: 'get_templates_error', message: (error as Error).message }));
    return NextResponse.json({ error: '获取模板失败' }, { status: 500 });
  }
}

// 创建新模板（仅 admin/sudo）
export async function POST(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  if (session.role !== 'admin' && session.role !== 'sudo') {
    return NextResponse.json({ error: '需要管理员权限' }, { status: 403 });
  }

  try {
    const body = await req.json();
    const { name, description, title, labels, assignees, fields, body: templateBody } = body;

    if (!name || !templateBody) {
      return NextResponse.json({ error: '缺少必需字段' }, { status: 400 });
    }

    const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
    const fileName = `${slug}.md`;
    const filePath = `tickets/${fileName}`;

    const frontMatter: any = {
      name,
      description: description || '',
      title: title || `[${name}] `,
      labels: labels || [],
      assignees: assignees || [],
      fields: (fields || []).map((f: any) => ({
        name: f.name,
        label: f.label,
        type: f.type || 'input',
        ...(f.options ? { options: f.options } : {}),
        required: f.required !== false,
      })),
    };

    const fileContent = `---\n${yaml.dump(frontMatter)}---\n\n${templateBody}`;

    const githubRes = await fetch(`${new URL(req.url).origin}/api/github`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'create',
        path: filePath,
        content: fileContent,
        message: `feat: add ticket template ${name}`,
      }),
    });

    if (!githubRes.ok) {
      const err = await githubRes.json();
      return NextResponse.json({ error: err.error || '创建模板失败' }, { status: 500 });
    }

    return NextResponse.json({ success: true, slug: `/${slug}` });
  } catch (error: any) {
    console.error('create_template_error:', error.message);
    return NextResponse.json({ error: '创建模板失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSession } from '@/lib/auth';
import { getTicketTemplate, renderTicketBody } from '@/lib/tickets';
import { getEnvConfig } from '@/lib/env';

/**
 * 创建工单
 * - 根据模板生成 markdown 内容
 * - 提交到 GitHub 仓库的 tickets/ 目录
 */
export async function POST(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const { templateSlug, formData, title } = await req.json();

    if (!templateSlug || !formData) {
      return NextResponse.json({ error: '缺少必填字段' }, { status: 400 });
    }

    // 获取模板
    const template = getTicketTemplate(templateSlug);
    if (!template) {
      return NextResponse.json({ error: '模板不存在' }, { status: 404 });
    }

    // 渲染工单内容
    const body = renderTicketBody(template, formData);

    // 生成工单文件名（使用时间戳）
    const timestamp = Date.now().toString(36);
    const slug = `/${template.slug}/${timestamp}`;
    const fileName = `tickets${slug}.md`;

    // 构建 front matter
    const frontMatter: Record<string, any> = {
      title: title || template.title || 'Untitled',
      author: session.email,
      date: new Date().toISOString(),
      labels: template.labels,
      status: 'open',
      assignees: template.assignees,
      template: template.name,
    };

    // 获取 GitHub 配置
    const env = getEnvConfig();
    if (!env.githubRepo || !env.githubToken) {
      return NextResponse.json({ error: 'GitHub 配置缺失' }, { status: 500 });
    }

    // 提交到 GitHub
    const postRes = await fetch('/api/github', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'create',
        path: fileName,
        frontMatter,
        body,
        message: `create ticket: ${frontMatter.title}`,
      }),
    });
    if (!postRes.ok) {
      throw new Error('Failed to create ticket on GitHub');
    }
    const result = await postRes.json();

    return NextResponse.json({ success: true, slug, result });
  } catch (error) {
    console.error(JSON.stringify({ type: 'create_ticket_error', message: (error as Error).message }));
    return NextResponse.json({ error: '创建工单失败' }, { status: 500 });
  }
}

/**
 * 获取工单列表（从 GitHub 读取）
 * - Admin/Sudo 可见全部
 * - 普通用户只能看自己的
 */
export async function GET(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const env = getEnvConfig();
    if (!env.githubRepo || !env.githubToken) {
      return NextResponse.json({ error: 'GitHub 配置缺失' }, { status: 500 });
    }

    // 列出 tickets/ 目录下的文件
    const listRes = await fetch(`/api/github?path=tickets`);
    if (!listRes.ok) {
      if (listRes.status === 404) return NextResponse.json([]);
      throw new Error('Failed to list tickets from GitHub');
    }
    const data = await listRes.json();

    if (!Array.isArray(data)) {
      return NextResponse.json([]);
    }

    // 读取每个工单文件
    const tickets = await Promise.all(
      data.map(async (file: any) => {
        try {
          const contentRes = await fetch(`/api/github?path=${file.path}`);
          if (!contentRes.ok) return null;
          const { frontMatter } = await contentRes.json();

          const author = frontMatter.author;
          const isAdmin = session.role === 'admin' || session.role === 'sudo';

          // 权限控制：admin/sudo 看全部，普通用户只看自己的
          if (!isAdmin && author !== session.email) {
            return null;
          }

          return {
            slug: file.path.replace(/^tickets/, '').replace(/\.md$/, ''),
            title: frontMatter.title || file.name,
            author,
            date: frontMatter.date,
            labels: frontMatter.labels || [],
            status: frontMatter.status || 'open',
            template: frontMatter.template,
          };
        } catch {
          return null;
        }
      })
    );

    return NextResponse.json(tickets.filter(Boolean));
  } catch (error: any) {
    if (error.status === 404) {
      return NextResponse.json([]);
    }
    console.error(JSON.stringify({ type: 'list_tickets_error', message: (error as Error).message }));
    return NextResponse.json({ error: '获取工单列表失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import { getSession } from '@/lib/auth';

// 默认用户组
const defaultGroups = [
  { id: 'sudo', name: '超级管理员组', description: '拥有所有权限的管理员组', isDefault: true, createdAt: new Date(0).toISOString() },
  { id: 'admin', name: '管理员组', description: '普通管理员组', isDefault: true, createdAt: new Date(0).toISOString() },
  { id: 'default', name: '默认用户组', description: '普通用户默认组', isDefault: true, createdAt: new Date(0).toISOString() },
];

// 计算用户组的成员数量
async function calculateMemberCount(db: any, groupId: string): Promise<number> {
  const userListStr = await db.get('users:all:list');
  if (!userListStr) return 0;

  const uids = JSON.parse(userListStr);
  let count = 0;

  for (const uid of uids) {
    const userStr = await db.get(`user:uid:${uid}`);
    if (userStr) {
      const user = JSON.parse(userStr);
      if (user.userGroup === groupId) {
        count++;
      }
    }
  }

  return count;
}

// 获取用户组列表或单个用户组
export async function GET(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: '未登录' }, { status: 401 });
  }

  try {
    const db = getDb();
    const { searchParams } = new URL(req.url);
    const groupId = searchParams.get('id');

    const groupsStr = await db.get('user-groups:list');
    const groups = groupsStr ? JSON.parse(groupsStr) : [];

    // 确保默认用户组存在
    const existingIds = groups.map((g: any) => g.id);
    for (const defaultGroup of defaultGroups) {
      if (!existingIds.includes(defaultGroup.id)) {
        groups.push(defaultGroup);
      }
    }

    // 计算成员数量
    for (const group of groups) {
      group.memberCount = await calculateMemberCount(db, group.id);
    }

    // 如果指定了 id，返回单个用户组
    if (groupId) {
      const group = groups.find((g: any) => g.id === groupId);
      if (!group) {
        return NextResponse.json({ error: '用户组不存在' }, { status: 404 });
      }
      return NextResponse.json(group);
    }

    return NextResponse.json(groups);
  } catch (error: any) {
    return NextResponse.json({ error: '获取用户组失败' }, { status: 500 });
  }
}

// 生成用户组 ID：adc-{6位随机数字}
function generateGroupId(): string {
  const num = Math.floor(100000 + Math.random() * 900000); // 100000-999999
  return `adc-${num}`;
}

// 创建用户组（仅管理员）
export async function POST(req: NextRequest) {
  const session = await getSession();
  if (!session || (session.role !== 'admin' && session.role !== 'sudo')) {
    return NextResponse.json({ error: '无权限' }, { status: 403 });
  }

  try {
    const { name, description } = await req.json();

    if (!name) {
      return NextResponse.json({ error: '用户组名称不能为空' }, { status: 400 });
    }

    const db = getDb();
    const groupsStr = await db.get('user-groups:list');
    const groups = groupsStr ? JSON.parse(groupsStr) : [];

    // 确保默认用户组存在
    const existingIds = groups.map((g: any) => g.id);
    for (const defaultGroup of defaultGroups) {
      if (!existingIds.includes(defaultGroup.id)) {
        groups.push(defaultGroup);
      }
    }

    // 检查名称是否已存在
    if (groups.some((g: any) => g.name === name)) {
      return NextResponse.json({ error: '用户组名称已存在' }, { status: 409 });
    }

    // 生成唯一 ID
    let newId = generateGroupId();
    while (groups.some((g: any) => g.id === newId)) {
      newId = generateGroupId();
    }

    const newGroup = {
      id: newId,
      name,
      description: description || '',
      isDefault: false,
      createdAt: new Date().toISOString(),
      createdBy: session.uid,
      memberCount: 0,
    };

    groups.push(newGroup);
    await db.set('user-groups:list', JSON.stringify(groups));

    return NextResponse.json({ success: true, group: newGroup });
  } catch (error: any) {
    return NextResponse.json({ error: '创建用户组失败' }, { status: 500 });
  }
}

// 更新用户组（仅管理员）
export async function PATCH(req: NextRequest) {
  const session = await getSession();
  if (!session || (session.role !== 'admin' && session.role !== 'sudo')) {
    return NextResponse.json({ error: '无权限' }, { status: 403 });
  }

  try {
    const { id, name, description } = await req.json();

    if (!id) {
      return NextResponse.json({ error: '用户组ID不能为空' }, { status: 400 });
    }

    // 不允许修改系统默认组
    if (['sudo', 'admin', 'default'].includes(id)) {
      return NextResponse.json({ error: '不能修改系统默认用户组' }, { status: 403 });
    }

    if (!name && !description) {
      return NextResponse.json({ error: '需要提供要更新的字段' }, { status: 400 });
    }

    const db = getDb();
    const groupsStr = await db.get('user-groups:list');
    const groups = groupsStr ? JSON.parse(groupsStr) : [];

    const groupIndex = groups.findIndex((g: any) => g.id === id);
    if (groupIndex === -1) {
      return NextResponse.json({ error: '用户组不存在' }, { status: 404 });
    }

    // 只更新允许的字段
    if (name) {
      // 检查名称是否与其他用户组重复（排除自己）
      const nameExists = groups.some((g: any, idx: number) => idx !== groupIndex && g.name === name);
      if (nameExists) {
        return NextResponse.json({ error: '用户组名称已存在' }, { status: 409 });
      }
      groups[groupIndex].name = name;
    }
    if (description !== undefined) {
      groups[groupIndex].description = description;
    }

    await db.set('user-groups:list', JSON.stringify(groups));

    return NextResponse.json({ success: true, group: groups[groupIndex] });
  } catch (error: any) {
    return NextResponse.json({ error: '更新用户组失败' }, { status: 500 });
  }
}

// 删除用户组（仅管理员）
export async function DELETE(req: NextRequest) {
  const session = await getSession();
  if (!session || (session.role !== 'admin' && session.role !== 'sudo')) {
    return NextResponse.json({ error: '无权限' }, { status: 403 });
  }

  try {
    const { id } = await req.json();

    // 不允许删除系统默认组
    if (['sudo', 'admin', 'default'].includes(id)) {
      return NextResponse.json({ error: '不能删除系统默认用户组' }, { status: 403 });
    }

    const db = getDb();
    const groupsStr = await db.get('user-groups:list');
    const groups = groupsStr ? JSON.parse(groupsStr) : [];

    const filtered = groups.filter((g: any) => g.id !== id);
    await db.set('user-groups:list', JSON.stringify(filtered));

    return NextResponse.json({ success: true });
  } catch (error: any) {
    return NextResponse.json({ error: '删除用户组失败' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import { getSession } from '@/lib/auth';

export async function GET() {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const db = getDb();
    const userStr = await db.get(`user:uid:${session.uid}`);
    if (!userStr) {
      return NextResponse.json({ error: '用户不存在' }, { status: 404 });
    }

    const user = JSON.parse(userStr);
    return NextResponse.json({
      success: true,
      user: {
        uid: user.uid,
        email: user.email,
        username: user.username,
        name: user.name,
        avatar: user.avatar,
        role: user.role,
        userGroup: user.userGroup,
        createdAt: user.createdAt,
        status: user.status,
      }
    });
  } catch (error: any) {
    console.error(JSON.stringify({ type: 'get_profile_error', message: error.message }));
    return NextResponse.json({ error: '获取用户资料失败' }, { status: 500 });
  }
}

export async function PUT(req: NextRequest) {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json({ error: '未登录' }, { status: 401 });
    }

    const body = await req.json();
    const { avatar, username, name } = body;

    if (avatar === undefined && username === undefined && name === undefined) {
      return NextResponse.json({ error: '没有要更新的字段' }, { status: 400 });
    }

    if (username !== undefined && username !== null) {
      if (!/^[a-zA-Z0-9_]{3,20}$/.test(username)) {
        return NextResponse.json({ error: '用户名只能包含字母、数字和下划线，3-20个字符' }, { status: 400 });
      }
    }

    const db = getDb();
    const userStr = await db.get(`user:uid:${session.uid}`);
    if (!userStr) {
      return NextResponse.json({ error: '用户不存在' }, { status: 404 });
    }

    const user = JSON.parse(userStr);

    if (username !== undefined && username !== null && username !== user.username) {
      const existingUsername = await db.get(`user:username:${username}`);
      if (existingUsername) {
        return NextResponse.json({ error: '该用户名已被使用' }, { status: 409 });
      }
    }

    if (user.username && username !== undefined && username !== user.username) {
      await db.del(`user:username:${user.username}`);
    }

    if (avatar !== undefined) user.avatar = avatar;
    if (username !== undefined) user.username = username || null;
    if (name !== undefined) user.name = name;

    await db.set(`user:uid:${session.uid}`, JSON.stringify(user));

    if (username) {
      await db.set(`user:username:${username}`, session.uid);
    }

    return NextResponse.json({
      success: true,
      user: {
        uid: user.uid,
        email: user.email,
        username: user.username,
        name: user.name,
        avatar: user.avatar,
        role: user.role,
        userGroup: user.userGroup,
      },
      message: '资料更新成功'
    }, { status: 201 });
  } catch (error: any) {
    console.error(JSON.stringify({ type: 'update_profile_error', message: error.message }));
    return NextResponse.json({ error: '更新用户资料失败' }, { status: 500 });
  }
}

