    if (!session || (session.role !== 'sudo' && session.role !== 'admin')) {
      return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
    }

    const { uid } = await params;
    const db = getDb();
    const userStr = await db.get(`user:uid:${uid}`);

    if (!userStr) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    const user = JSON.parse(userStr);
    const body = await req.json();
    const { role, userGroup } = body;

    // Validate and update role
    if (role !== undefined) {
      const validRoles: UserRole[] = ['user', 'admin', 'sudo'];
      if (!validRoles.includes(role)) {
        return NextResponse.json({ error: 'Invalid role' }, { status: 400 });
      }
      user.role = role;
    }

    // Validate and update userGroup
    if (userGroup !== undefined) {
      if (userGroup && !(await groupExists(db, userGroup))) {
        return NextResponse.json({ error: 'User group not found' }, { status: 404 });
      }
      user.userGroup = userGroup || undefined;
    }

    await db.set(`user:uid:${uid}`, JSON.stringify(user));
    return NextResponse.json({
      uid: user.uid,
      name: user.name,
      email: user.email,
      role: user.role,
      userGroup: user.userGroup,
      status: user.status,
    });
  } catch (error) {
    console.error('User PATCH error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/db';
import { getSession, requireSudo } from '@/lib/auth';

/**
 * Users API
 * GET /api/users - List all users (sudo only)
 * GET /api/users/[username] - Get user by username
 */

export async function GET(req: NextRequest) {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const db = getDb();
    const { searchParams } = new URL(req.url);
    const username = searchParams.get('username');
    const uid = searchParams.get('uid');

    // Get specific user by username (email prefix)
    if (username) {
      // Try to find by username (we store email, so extract username from email)
      const userListStr = await db.get('users:all:list');
      if (!userListStr) {
        return NextResponse.json({ error: 'User not found' }, { status: 404 });
      }

      const users = JSON.parse(userListStr);
      let userData = null;

      for (const uid of users) {
        const userStr = await db.get(`user:uid:${uid}`);
        if (userStr) {
          const user = JSON.parse(userStr);
          const userUsername = user.email.split('@')[0];
          if (userUsername === username || user.uid === username) {
            userData = {
              uid: user.uid,
              name: user.name,
              email: user.email,
              createdAt: user.createdAt,
              role: user.role,
              userGroup: user.userGroup,
            };
            break;
          }
        }
      }

      if (!userData) {
        return NextResponse.json({ error: 'User not found' }, { status: 404 });
      }

      return NextResponse.json(userData);
    }

    // Get specific user by UID
    if (uid) {
      const userStr = await db.get(`user:uid:${uid}`);
      if (!userStr) {
        return NextResponse.json({ error: 'User not found' }, { status: 404 });
      }
      const user = JSON.parse(userStr);
      return NextResponse.json({
        uid: user.uid,
        name: user.name,
        email: user.email,
        createdAt: user.createdAt,
        role: user.role,
        userGroup: user.userGroup,
      });
    }

    // List all users (sudo only)
    if (session.role !== 'sudo' && session.role !== 'admin') {
      return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
    }

    const userListStr = await db.get('users:all:list');
    if (!userListStr) {
      return NextResponse.json([]);
    }

    const users = JSON.parse(userListStr);
    const allUsers = [];

    for (const uid of users) {
      const userStr = await db.get(`user:uid:${uid}`);
      if (userStr) {
        const user = JSON.parse(userStr);
        allUsers.push({
          uid: user.uid,
          name: user.name,
          email: user.email,
          createdAt: user.createdAt,
          role: user.role,
          status: user.status,
          userGroup: user.userGroup,
        });
      }
    }

    return NextResponse.json(allUsers);
  } catch (error) {
    console.error('Users API error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { Webhook } from 'svix';
import { getDb } from '@/lib/db';

/**
 * Clerk Webhook 处理
 * 同步 Clerk 用户事件到 Originium Kernel
 */
export async function POST(req: NextRequest) {
  const WEBHOOK_SECRET = process.env.CLERK_WEBHOOK_SECRET;
  if (!WEBHOOK_SECRET) {
    return NextResponse.json({ error: 'Webhook secret not configured' }, { status: 500 });
  }

  // 验证 webhook 签名
  const svixId = req.headers.get('svix-id');
  const svixTimestamp = req.headers.get('svix-timestamp');
  const svixSignature = req.headers.get('svix-signature');

  if (!svixId || !svixTimestamp || !svixSignature) {
    return NextResponse.json({ error: 'Missing svix headers' }, { status: 400 });
  }

  let payload: any;
  try {
    const body = await req.text();
    const wh = new Webhook(WEBHOOK_SECRET);
    payload = wh.verify(body, {
      'svix-id': svixId,
      'svix-timestamp': svixTimestamp,
      'svix-signature': svixSignature,
    }) as any;
  } catch {
    return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
  }

  const db = getDb();
  const eventType = payload.type;

  try {
    switch (eventType) {
      case 'user.created': {
        // Clerk 用户创建时，存储映射关系（暂不创建 Originium Kernel 用户）
        const clerkId = payload.data.id;
        const email = payload.data.email_addresses?.[0]?.email_address;
        if (email) {
          await db.set(`clerk:email:${email}`, clerkId);
        }
        break;
      }

      case 'user.updated': {
        const clerkId = payload.data.id;
        const email = payload.data.email_addresses?.[0]?.email_address;
        if (email) {
          await db.set(`clerk:email:${email}`, clerkId);
        }
        break;
      }

      case 'user.deleted': {
        // Clerk 用户删除时，清理绑定关系
        const clerkId = payload.data.id;
        const boundUid = await db.get(`clerk:user:${clerkId}`);
        if (boundUid) {
          await db.del(`clerk:user:${clerkId}`);
          await db.del(`user:clerk:${boundUid}`);
          // 尝试清除 Prisma 中的 clerkId
          try {
            const { prisma } = await import('@/lib/db');
            await prisma.user.updateMany({
              where: { clerkId },
              data: { clerkId: null, clerkLinkedAt: null },
            });
          } catch {}
        }
        break;
      }
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Clerk webhook error:', error);
    return NextResponse.json({ error: 'Internal error' }, { status: 500 });
  }
}

