/**
 * Clerk 账户绑定页面
 * 流程：输入邮箱 → 发送验证码 → 输入验证码 → 绑定
 */
export default function ClerkBindPage() {
  const { user } = useUser();
  const router = useRouter();
  const [step, setStep] = useState(0);
  const [email, setEmail] = useState('');
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [codeSent, setCodeSent] = useState(false);
  const [countdown, setCountdown] = useState(0);

  /** 发送验证码 */
  const handleSendCode = async () => {
    if (!email.includes('@')) {
      message.error('请输入有效的邮箱地址');
      return;
    }
    setLoading(true);
    try {
      const res = await fetch('/api/auth/bind-send-code', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });
      const data = await res.json();
      if (res.ok) {
        setCodeSent(true);
        setStep(1);
        message.success('验证码已发送');
        // 60 秒倒计时
        setCountdown(60);
        const timer = setInterval(() => {
          setCountdown((prev) => {
            if (prev <= 1) { clearInterval(timer); return 0; }
            return prev - 1;
          });
        }, 1000);
      } else {
        message.error(data.error || '发送失败');
      }
    } catch {
      message.error('网络错误');
    } finally {
      setLoading(false);
    }
  };

  /** 验证并绑定 */
  const handleVerifyAndBind = async () => {
    if (!code || code.length < 4) {
      message.error('请输入验证码');
      return;
    }
    setLoading(true);
    try {
      const res = await fetch('/api/auth/bind-verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, code }),
      });
      const data = await res.json();
      if (res.ok) {
        setStep(2);
        message.success('账户绑定成功！');
        setTimeout(() => router.push('/dashboard'), 1500);
      } else {
        message.error(data.error || '验证失败');
      }
    } catch {
      message.error('网络错误');
    } finally {
      setLoading(false);
