                  placeholder="your@email.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  prefix={<Mail size={16} className="text-zinc-400" />}
                  className="h-12 rounded-xl"
                />
              </div>
              <Button
                type="primary"
                size="large"
                block
                loading={loading}
                onClick={handleSendCode}
                className="h-12 rounded-xl bg-zinc-900"
                icon={<ArrowRight size={16} />}
              >
                发送验证码
              </Button>
            </>
          )}

          {step === 1 && (
            <>
              <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <Shield size={24} className="text-amber-600" />
              </div>
              <h1 className="text-xl font-bold text-zinc-900 mb-2 text-center">
                验证身份
              </h1>
              <p className="text-zinc-400 text-sm mb-8 text-center">
                验证码已发送至 <strong className="text-zinc-700">{email}</strong>
              </p>
              <div className="mb-6">
                <label className="block text-sm font-medium text-zinc-700 mb-2">
                  验证码
                </label>
                <Input
                  size="large"
                  placeholder="输入 6 位验证码"
                  value={code}
                  onChange={(e) => setCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                  maxLength={6}
                  prefix={<KeyRound size={16} className="text-zinc-400" />}
                  className="h-12 rounded-xl text-center text-lg tracking-[0.5em]"
                />
              </div>
              <div className="space-y-3">
                <Button
                  type="primary"
                  size="large"
                  block
                  loading={loading}
                  onClick={handleVerifyAndBind}
                  className="h-12 rounded-xl bg-zinc-900"
                >
                  验证并绑定
                </Button>
                <Button
                  size="large"
                  block
                  disabled={countdown > 0}
                  onClick={handleSendCode}
                  className="h-12 rounded-xl"
                >
                  {countdown > 0 ? `${countdown}s 后重新发送` : '重新发送验证码'}
                </Button>
              </div>
            </>
          )}

          {step === 2 && (
            <div className="text-center">
              <div className="w-16 h-16 bg-emerald-50 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <CheckCircle2 size={32} className="text-emerald-600" />
              </div>
              <h1 className="text-xl font-bold text-zinc-900 mb-2">
                绑定完成
              </h1>
              <p className="text-zinc-400 text-sm">
                正在跳转到控制台...
              </p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import Link from 'next/link';
import { useSearchParams } from 'next/navigation';
import { useAuth } from '@/hooks/use-auth';
import { useI18n } from '@/hooks/use-i18n';
import {
  Edit, Trash2, Plus, Eye, RotateCcw, Globe, FileEdit, ArrowRight, Search,
} from 'lucide-react';
import { Button, Input, Tag, Spin, Popconfirm, message } from 'antd';

interface ArticleItem {
  id: string;
  slug?: string;
  title: string;
  author?: string;
  date?: string;
  tags?: string[];
  cover?: string;
  description?: string;
  status: 'published' | 'draft' | 'pending_deletion';
}

export default function ArticlesPage() {
  const { user } = useAuth();
  const { t, locale } = useI18n();
  const searchParams = useSearchParams();
  const status = searchParams?.get('status');
  const isRecycleBin = status === 'pending_deletion';

  const [articles, setArticles] = useState<ArticleItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    if (!user) return;
    const fetchArticles = async () => {
      try {
        const res = await fetch('/api/articles');
        if (res.ok) {
          const data = await res.json();
          const filtered = isRecycleBin
            ? data.filter((a: ArticleItem) => a.status === 'pending_deletion')
            : data.filter((a: ArticleItem) => a.status !== 'pending_deletion');
          setArticles(filtered);
        }
      } catch (error) {
        console.error('获取文章列表失败:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchArticles();
  }, [user, isRecycleBin]);

  const handleDelete = async (id: string) => {
    try {
      const res = await fetch(`/api/articles/${id}`, { method: 'DELETE' });
      if (res.ok) {
        setArticles(articles.filter(a => a.id !== id));
        message.success(locale === 'zh-CN' ? '已删除' : 'Deleted');
      }
    } catch (error) {
      message.error(locale === 'zh-CN' ? '删除失败' : 'Delete failed');
    }
  };

  const handleRestore = async (id: string) => {
    try {
      const res = await fetch(`/api/articles/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: 'draft' }),
      });
      if (res.ok) {
        setArticles(articles.filter(a => a.id !== id));
        message.success(locale === 'zh-CN' ? '已恢复' : 'Restored');
      }
    } catch (error) {
      message.error(locale === 'zh-CN' ? '恢复失败' : 'Restore failed');
    }
  };

  const filteredArticles = articles.filter(a =>
    !searchTerm || a.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (!user) return null;

  if (loading) {
    return (
      <div className="flex items-center justify-center h-[60vh]">
        <Spin size="large" />
      </div>
    );
  }

  return (
    <div className="p-6 md:p-10 max-w-6xl mx-auto">
      {/* 标题栏 */}
      <div className="flex items-start justify-between mb-8">
        <div>
          <h1 className="text-2xl font-black tracking-tight text-zinc-900">
            {isRecycleBin
              ? locale === 'zh-CN' ? '回收站' : 'Recycle Bin'
              : locale === 'zh-CN' ? '文章管理' : 'Article Management'}
          </h1>
          {isRecycleBin && (
            <p className="text-zinc-400 text-sm mt-1">
              {locale === 'zh-CN' ? '待删除的文章，30天后自动删除' : 'Pending deletion, auto-delete after 30 days'}
            </p>
          )}
        </div>
        <div className="flex items-center gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-300" size={16} />
            <Input
              placeholder={locale === 'zh-CN' ? '搜索文章...' : 'Search articles...'}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-9 h-10 rounded-xl w-52"
              size="middle"
            />
          </div>
          {!isRecycleBin && (
            <Link href="/editor">
              <Button type="primary" icon={<Plus size={14} />} className="bg-zinc-900 rounded-xl h-10">
                {locale === 'zh-CN' ? '新建文章' : 'New Article'}
              </Button>
            </Link>
          )}
        </div>
      </div>

      {/* 文章列表 */}
      <div className="bg-white rounded-2xl border border-zinc-100 overflow-hidden">
        {/* 表头 */}
        <div className="grid grid-cols-12 gap-4 px-6 py-3 bg-zinc-50 border-b border-zinc-100 text-xs font-bold text-zinc-500 uppercase tracking-wider">
          <div className="col-span-5">{locale === 'zh-CN' ? '标题' : 'Title'}</div>
          <div className="col-span-2">{locale === 'zh-CN' ? '状态' : 'Status'}</div>
          <div className="col-span-2">{locale === 'zh-CN' ? '作者' : 'Author'}</div>
          <div className="col-span-3 text-right">{locale === 'zh-CN' ? '操作' : 'Actions'}</div>
        </div>

        {filteredArticles.length > 0 ? (
          <div className="divide-y divide-zinc-50">
            {filteredArticles.map((article) => (
              <div key={article.id} className="grid grid-cols-12 gap-4 px-6 py-4 items-center hover:bg-zinc-50/50 transition-colors">
                {/* 标题 */}
                <div className="col-span-5 min-w-0">
                  <div className="text-sm font-semibold text-zinc-900 truncate">{article.title}</div>
                  {article.description && (
                    <div className="text-xs text-zinc-400 truncate mt-0.5">{article.description}</div>
                  )}
                </div>

                {/* 状态 */}
                <div className="col-span-2">
                  <Tag
                    color={
                      article.status === 'published' ? 'success'
                      : article.status === 'pending_deletion' ? 'error'
                      : 'warning'
                    }
                    className="rounded-lg text-xs"
                    icon={
                      article.status === 'published' ? <Globe size={10} />
                      : article.status === 'pending_deletion' ? <Trash2 size={10} />
                      : <FileEdit size={10} />
                    }
                  >
                    {article.status === 'published'
                      ? locale === 'zh-CN' ? '已发布' : 'Published'
                      : article.status === 'pending_deletion'
                      ? locale === 'zh-CN' ? '待删除' : 'Pending'
                      : locale === 'zh-CN' ? '草稿' : 'Draft'}
                  </Tag>
                </div>

                {/* 作者 */}
                <div className="col-span-2 text-sm text-zinc-500 truncate">
                  {article.author || '—'}
                </div>

                {/* 操作 */}
                <div className="col-span-3 flex items-center gap-2 justify-end">
                  {isRecycleBin ? (
                    <>
                      <Button
                        size="small"
                        icon={<RotateCcw size={13} />}
                        onClick={() => handleRestore(article.id)}
                        className="rounded-lg text-emerald-600 border-emerald-200 hover:border-emerald-400"
                      >
                        {locale === 'zh-CN' ? '恢复' : 'Restore'}
                      </Button>
                      <Popconfirm
                        title={locale === 'zh-CN' ? '永久删除？此操作不可恢复！' : 'Permanently delete?'}
                        onConfirm={() => handleDelete(article.id)}
                        okText={locale === 'zh-CN' ? '删除' : 'Delete'}
                        cancelText={locale === 'zh-CN' ? '取消' : 'Cancel'}
                        okButtonProps={{ danger: true }}
                      >
                        <Button size="small" danger icon={<Trash2 size={13} />} className="rounded-lg">
                          {locale === 'zh-CN' ? '永久删除' : 'Delete'}
                        </Button>
                      </Popconfirm>
                    </>
                  ) : (
                    <>
                      {article.status === 'published' && article.slug && (
                        <Link href={`/posts${article.slug}`}>
                          <Button size="small" icon={<Eye size={13} />} className="rounded-lg">
                            {locale === 'zh-CN' ? '查看' : 'View'}
                          </Button>
                        </Link>
                      )}
                      <Link href={`/editor?id=${article.id}`}>
                        <Button size="small" icon={<Edit size={13} />} className="rounded-lg">
                          {locale === 'zh-CN' ? '编辑' : 'Edit'}
                        </Button>
                      </Link>
                      <Popconfirm
                        title={locale === 'zh-CN' ? '确定删除这篇文章？' : 'Delete this article?'}
                        onConfirm={() => handleDelete(article.id)}
                        okText={locale === 'zh-CN' ? '删除' : 'Delete'}
                        cancelText={locale === 'zh-CN' ? '取消' : 'Cancel'}
                        okButtonProps={{ danger: true }}
                      >
                        <Button size="small" danger icon={<Trash2 size={13} />} className="rounded-lg" />
                      </Popconfirm>
                    </>
                  )}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="py-16 text-center">
            <p className="text-zinc-400">
              {isRecycleBin
                ? locale === 'zh-CN' ? '回收站为空' : 'Recycle bin is empty'
                : locale === 'zh-CN' ? '暂无文章' : 'No articles yet'}
            </p>
            {!isRecycleBin && (
              <Link href="/editor" className="mt-4 inline-block">
                <Button type="primary" icon={<Plus size={14} />} className="bg-zinc-900 rounded-xl mt-4">
                  {locale === 'zh-CN' ? '创建第一篇文章' : 'Create first article'}
                </Button>
              </Link>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { useAuth } from '@/hooks/use-auth';
import { useI18n } from '@/hooks/use-i18n';
import { useRouter } from 'next/navigation';
import {
  FileText, Users, Clock, CheckCircle, Plus, Settings,
  BookOpen, ArrowRight, Shield, UserCog, Trash2, Activity,
  Globe, PenLine, Sparkles,
} from 'lucide-react';
import { Button, Spin, Tag } from 'antd';
import Link from 'next/link';

interface Stats {
  totalArticles: number;
  publishedArticles: number;
  draftArticles: number;
  totalUsers: number;
  pendingDeletion: number;
}

interface RecentArticle {
  id: string;
  title: string;
  status: string;
  slug?: string;
  updatedAt: string;
}

export default function DashboardPage() {
  const { user, userRole, isSudo } = useAuth();
  const { t, locale } = useI18n();
  const router = useRouter();

  const [stats, setStats] = useState<Stats>({
    totalArticles: 0,
    publishedArticles: 0,
    draftArticles: 0,
    totalUsers: 0,
    pendingDeletion: 0,
  });
  const [recentArticles, setRecentArticles] = useState<RecentArticle[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const articlesRes = await fetch('/api/articles');
        if (articlesRes.ok) {
          const articles = await articlesRes.json();
          const published = articles.filter((a: any) => a.status === 'published').length;
          const drafts = articles.filter((a: any) => a.status === 'draft').length;
          const pending = articles.filter((a: any) => a.status === 'pending_deletion').length;
          setStats(prev => ({
            ...prev,
            totalArticles: articles.length,
            publishedArticles: published,
            draftArticles: drafts,
            pendingDeletion: pending,
          }));
          setRecentArticles(articles.slice(0, 5).map((a: any) => ({
            id: a.id,
            title: a.title,
            status: a.status,
            slug: a.slug,
            updatedAt: a.updatedAt || a.date || '',
          })));
        }
        if (isSudo) {
          const usersRes = await fetch('/api/users');
          if (usersRes.ok) {
            const users = await usersRes.json();
            setStats(prev => ({ ...prev, totalUsers: users.length }));
          }
        }
      } catch (error) {
        console.error('Failed to fetch stats:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [isSudo]);

  const statCards = [
    { title: t('dashboard.allArticles'), value: stats.totalArticles, icon: FileText, color: 'bg-zinc-900', textColor: 'text-white' },
    { title: t('dashboard.published'), value: stats.publishedArticles, icon: Globe, color: 'bg-emerald-500', textColor: 'text-white' },
    { title: t('dashboard.drafts'), value: stats.draftArticles, icon: Clock, color: 'bg-amber-500', textColor: 'text-white' },
    ...(isSudo ? [
      { title: t('dashboard.totalUsers'), value: stats.totalUsers, icon: Users, color: 'bg-blue-500', textColor: 'text-white' },
      { title: t('dashboard.pendingDeletion'), value: stats.pendingDeletion, icon: Trash2, color: 'bg-red-500', textColor: 'text-white' },
    ] : []),
  ];

  const userActions = [
    { label: t('sidebar.writeArticle'), icon: PenLine, href: '/editor', desc: locale === 'zh-CN' ? '创建新内容' : 'Create new content' },
    { label: t('sidebar.articleManagement'), icon: BookOpen, href: '/dashboard/articles', desc: locale === 'zh-CN' ? '管理所有文章' : 'Manage all articles' },
    { label: t('sidebar.recycleBin'), icon: Trash2, href: '/dashboard/articles?status=pending_deletion', desc: locale === 'zh-CN' ? '恢复或永久删除' : 'Restore or permanently delete' },
  ];

  const adminActions = [
    { label: t('sidebar.userManagement'), icon: UserCog, href: '/admin/users', desc: locale === 'zh-CN' ? '用户与权限' : 'Users & permissions' },
    { label: t('sidebar.userGroups'), icon: Shield, href: '/admin/groups', desc: locale === 'zh-CN' ? '用户组配置' : 'Group configuration' },
    { label: t('sidebar.systemConfig'), icon: Settings, href: '/admin/config', desc: locale === 'zh-CN' ? '站点与外观' : 'Site & appearance' },
    { label: t('sidebar.envVariables'), icon: Activity, href: '/admin/env', desc: locale === 'zh-CN' ? '检查配置状态' : 'Check config status' },
  ];

  const quickActions = isSudo ? [...userActions, ...adminActions] : userActions;

  if (loading) {
    return (
      <div className="flex items-center justify-center h-[60vh]">
        <Spin size="large" />
      </div>
    );
  }

  return (
    <div className="p-6 md:p-10 max-w-6xl mx-auto">
      {/* 欢迎区域 */}
      <div className="mb-10">
        <div className="flex items-center gap-3 mb-2">
          <h1 className="text-3xl font-black tracking-tight text-zinc-900">
            {t('dashboard.welcomeBack')}，{user?.name || '用户'}
          </h1>
          {isSudo && (
            <Tag color="gold" className="rounded-lg text-xs font-bold">
              {userRole === 'sudo' ? t('dashboard.superAdmin') : t('dashboard.admin')}
            </Tag>
          )}
        </div>
        <p className="text-zinc-400 text-base">
          {isSudo ? t('dashboard.adminConsole') : t('dashboard.contentConsole')}
        </p>
      </div>

      {/* 统计卡片 */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-4 mb-10">
        {statCards.map((card, index) => {
          const Icon = card.icon;
          return (
            <div
              key={index}
              className="bg-white rounded-2xl border border-zinc-100 p-5 hover:shadow-lg hover:shadow-zinc-100 transition-all duration-300 group"
            >
              <div className={`w-10 h-10 ${card.color} rounded-xl flex items-center justify-center mb-4 group-hover:scale-110 transition-transform duration-300`}>
                <Icon size={18} className={card.textColor} />
              </div>
              <div className="text-3xl font-black text-zinc-900 mb-1">{card.value}</div>
              <div className="text-xs text-zinc-400 font-medium">{card.title}</div>
            </div>
          );
        })}
      </div>

      {/* 快捷操作 */}
      <div className="mb-10">
        <h2 className="text-lg font-bold text-zinc-900 mb-4">{t('dashboard.quickActions')}</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
          {quickActions.map((action, index) => {
            const Icon = action.icon;
            return (
              <Link key={index} href={action.href} className="group">
                <div className="bg-white rounded-2xl border border-zinc-100 p-5 hover:border-zinc-300 hover:shadow-md transition-all duration-300">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 bg-zinc-50 rounded-xl flex items-center justify-center group-hover:bg-zinc-900 transition-colors duration-300">
                        <Icon size={16} className="text-zinc-400 group-hover:text-white transition-colors" />
                      </div>
                      <div>
                        <div className="text-sm font-semibold text-zinc-900">{action.label}</div>
                        <div className="text-xs text-zinc-400">{action.desc}</div>
                      </div>
                    </div>
                    <ArrowRight size={16} className="text-zinc-300 group-hover:text-zinc-900 group-hover:translate-x-1 transition-all" />
                  </div>
                </div>
              </Link>
            );
          })}
        </div>
      </div>

      {/* 最近文章 */}
      <div>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-zinc-900">{t('dashboard.recentArticles')}</h2>
          <Link href="/dashboard/articles">
            <Button size="small" icon={<ArrowRight size={14} />} className="rounded-xl">
              {t('dashboard.viewAll')}
            </Button>
          </Link>
        </div>

        <div className="bg-white rounded-2xl border border-zinc-100 overflow-hidden">
          {recentArticles.length > 0 ? (
            <div className="divide-y divide-zinc-50">
              {recentArticles.map((article) => (
                <div
                  key={article.id}
                  className="px-6 py-4 flex items-center justify-between hover:bg-zinc-50/50 transition-colors cursor-pointer group"
                  onClick={() => {
                    if (article.status === 'published' && article.slug) {
                      router.push(`/posts${article.slug}`);
                    } else {
                      router.push(`/editor?id=${article.id}`);
                    }
                  }}
                >
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-semibold text-zinc-900 truncate group-hover:text-zinc-600 transition-colors">
                      {article.title}
                    </div>
                    <div className="text-xs text-zinc-400 mt-0.5">
                      {article.updatedAt
                        ? new Date(article.updatedAt).toLocaleDateString(
                            locale === 'zh-CN' ? 'zh-CN' : 'en-US'
                          )
                        : '—'}
                    </div>
                  </div>
                  <div className="flex items-center gap-3 ml-4">
                    <Tag
                      color={
                        article.status === 'published'
                          ? 'success'
                          : article.status === 'pending_deletion'
                          ? 'error'
                          : 'warning'
                      }
                      className="rounded-lg text-xs"
                    >
                      {article.status === 'published'
                        ? t('article.published')
                        : article.status === 'pending_deletion'
                        ? t('article.pendingDeletion')
                        : t('article.draft')}
                    </Tag>
                    <ArrowRight size={14} className="text-zinc-300 group-hover:text-zinc-600 transition-colors" />
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="py-20 text-center">
              <div className="w-16 h-16 bg-zinc-50 rounded-2xl flex items-center justify-center mx-auto mb-4 text-zinc-300">
                <Sparkles size={28} />
              </div>
              <p className="text-zinc-400 mb-4">{t('dashboard.noArticles')}</p>
              <Link href="/editor">
                <Button type="primary" icon={<Plus size={14} />} className="bg-zinc-900 rounded-xl h-10">
                  {t('dashboard.writeFirstArticle')}
                </Button>
              </Link>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { useAuth } from '@/hooks/use-auth';
import { useI18n } from '@/hooks/use-i18n';
import { Button, Input, Form, message, Avatar } from 'antd';
import { User, AtSign, Image as ImageIcon, Save } from 'lucide-react';

export default function SettingsPage() {
  const { user, refresh } = useAuth();
  const { t } = useI18n();
  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (user) {
      form.setFieldsValue({
        avatarUrl: user.avatar || '',
        username: user.name || '',
        displayName: user.displayName || user.name || '',
      });
    }
  }, [user, form]);

  const handleSave = async (values: any) => {
    setLoading(true);
    try {
      const res = await fetch('/api/user/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          avatar: values.avatarUrl || undefined,
          username: values.username,
          name: values.displayName || undefined,
        }),
      });
      const data = await res.json();
      if (res.ok) {
        message.success(t('settings.saveSuccess'));
        await refresh();
      } else {
        message.error(data.error || t('settings.saveFailed'));
      }
