'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { motion } from 'motion/react';
import { Save, Trash2, ArrowLeft } from 'lucide-react';
import Link from 'next/link';
import { Input, Button, Form, message, Popconfirm } from 'antd';

interface GroupItem {
  slug: string;
  title: string;
  groupName?: string;
}

interface FaceData {
  slug: string;
  name: string;
  email: string;
  phone: string;
  group: string;
  content: string;
}

interface FaceFormProps {
  groups: GroupItem[];
  faceData?: FaceData;
  isEdit?: boolean;
}

export function FaceForm({ groups, faceData, isEdit = false }: FaceFormProps) {
  const router = useRouter();
  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [deleteLoading, setDeleteLoading] = useState(false);

  useEffect(() => {
    if (faceData) {
      form.setFieldsValue({
        name: faceData.name,
        email: faceData.email,
        phone: faceData.phone,
        group: faceData.group,
        content: faceData.content,
      });
    }
  }, [faceData, form]);

  const handleSubmit = async (values: any) => {
    setLoading(true);
    try {
      const payload: any = {
        name: values.name,
        email: values.email,
        phone: values.phone,
        group: values.group,
        content: values.content,
      };

      let response;
      if (isEdit && faceData) {
        payload.slug = faceData.slug;
        response = await fetch('/api/faces', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        });
      } else {
        response = await fetch('/api/faces', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        });
      }

      const data = await response.json();

      if (!response.ok) {
        message.error(data.error || '操作失败');
        return;
      }

      message.success(isEdit ? '联系人已更新' : '联系人已创建');
      router.push(`/faces${data.slug || faceData?.slug}`);
    } catch (error: any) {
      message.error(error.message || '操作失败');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!faceData) return;
    setDeleteLoading(true);
    try {
      const response = await fetch('/api/faces', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ slug: faceData.slug }),
      });

      const data = await response.json();

      if (!response.ok) {
        message.error(data.error || '删除失败');
        return;
      }

      message.success('联系人已删除');
      router.push('/faces');
    } catch (error: any) {
      message.error(error.message || '删除失败');
    } finally {
      setDeleteLoading(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
    >
      <Form
        form={form}
        layout="vertical"
        onFinish={handleSubmit}
        className="space-y-6"
        initialValues={{
          name: '',
          email: '',
          phone: '',
          group: groups.length > 0 ? groups[0].groupName || groups[0].slug.replace('/', '') : '',
          content: '',
        }}
      >
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Form.Item
            label={<span className="text-zinc-700 font-medium">姓名 *</span>}
            name="name"
            rules={[{ required: true, message: '请输入姓名' }]}
          >
            <Input
              placeholder="请输入姓名"
              className="h-12 rounded-xl"
              size="large"
            />
          </Form.Item>

          <Form.Item
            label={<span className="text-zinc-700 font-medium">邮箱</span>}
            name="email"
            rules={[
              { type: 'email', message: '请输入有效的邮箱地址' },
            ]}
          >
            <Input
              placeholder="请输入邮箱"
              className="h-12 rounded-xl"
              size="large"
            />
          </Form.Item>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Form.Item
            label={<span className="text-zinc-700 font-medium">电话</span>}
            name="phone"
          >
            <Input
              placeholder="请输入电话号码"
              className="h-12 rounded-xl"
              size="large"
            />
          </Form.Item>

          <Form.Item
            label={<span className="text-zinc-700 font-medium">分组 *</span>}
            name="group"
            rules={[{ required: true, message: '请选择分组' }]}
          >
            <select
              className="w-full h-12 rounded-xl border border-zinc-200 px-4 text-zinc-900 bg-white focus:outline-none focus:border-zinc-400 transition-colors"
              style={{ fontSize: '16px' }}
            >
              {groups.map((group) => {
                const groupValue = group.groupName || group.slug.replace('/', '');
                const groupLabel = group.title || groupValue;
                return (
                  <option key={group.slug} value={groupValue}>
                    {groupLabel}
                  </option>
                );
              })}
            </select>
          </Form.Item>
        </div>

        <Form.Item
          label={<span className="text-zinc-700 font-medium">备注信息</span>}
          name="content"
        >
          <textarea
            placeholder="请输入备注信息（支持 Markdown 格式）"
            className="w-full min-h-[200px] rounded-xl border border-zinc-200 p-4 text-zinc-900 bg-white focus:outline-none focus:border-zinc-400 transition-colors resize-y"
            style={{ fontSize: '16px', fontFamily: 'inherit' }}
          />
        </Form.Item>

        <div className="flex items-center justify-between pt-6 border-t border-zinc-100">
          <Link href={isEdit && faceData ? `/faces${faceData.slug}` : '/faces'}>
            <Button
              type="default"
              icon={<ArrowLeft size={16} />}
              className="h-12 px-6 rounded-xl"
            >
              返回
            </Button>
          </Link>

          <div className="flex gap-3">
            {isEdit && (
              <Popconfirm
                title="确认删除"
                description="删除后无法恢复，确定要删除此联系人吗？"
                onConfirm={handleDelete}
                okText="确定"
                cancelText="取消"
                okButtonProps={{ danger: true }}
              >
                <Button
                  type="default"
                  danger
                  icon={<Trash2 size={16} />}
                  loading={deleteLoading}
                  className="h-12 px-6 rounded-xl"
                >
                  删除
                </Button>
              </Popconfirm>
            )}
            <Button
              type="primary"
              htmlType="submit"
              icon={<Save size={16} />}
              loading={loading}
              className="h-12 px-8 rounded-xl bg-zinc-900 hover:bg-zinc-800"
            >
              {isEdit ? '保存修改' : '创建联系人'}
            </Button>
          </div>
        </div>
      </Form>
    </motion.div>
  );
}

'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { motion, AnimatePresence } from 'motion/react';
import { Search, Users, Sparkles, UserCircle } from 'lucide-react';
import { Input } from 'antd';

interface FaceItem {
  slug: string;
  title: string;
  date?: string;
  tags: string[];
  description?: string;
}

interface GroupItem {
  slug: string;
  title: string;
  description?: string;
  public: boolean;
  groupName?: string;
}

interface FacesListClientProps {
  faces: FaceItem[];
  groups: GroupItem[];
}

export function FacesListClient({ faces, groups }: FacesListClientProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeGroup, setActiveGroup] = useState<string | null>(null);

  const filteredFaces = faces.filter((f) => {
    const matchesSearch = !searchTerm ||
      f.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      f.description?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesGroup = !activeGroup ||
      f.slug.startsWith(activeGroup === '/' ? '/' : activeGroup + '/');
    return matchesSearch && matchesGroup;
  });

  const groupNames = [...new Set(groups.map((g) => g.groupName).filter(Boolean))] as string[];

  return (
    <div>
      {/* 搜索 */}
      <div className="flex flex-wrap gap-4 mb-10">
        <div className="relative flex-1 min-w-[240px]">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-300" size={20} />
          <Input
            placeholder="搜索联系人..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-12 h-12 text-base w-full rounded-2xl bg-white border-zinc-200"
            size="large"
            variant="outlined"
          />
        </div>
      </div>

      {/* 分组标签 */}
      {groupNames.length > 0 && (
        <div className="flex flex-wrap gap-2 mb-8">
          <button
            onClick={() => setActiveGroup(null)}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
              activeGroup === null
                ? 'bg-zinc-900 text-white'
                : 'bg-white text-zinc-600 border border-zinc-200 hover:border-zinc-300'
            }`}
          >
            全部
          </button>
          {groupNames.map((name) => (
            <button
              key={name}
              onClick={() => setActiveGroup(name)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
                activeGroup === name
                  ? 'bg-zinc-900 text-white'
                  : 'bg-white text-zinc-600 border border-zinc-200 hover:border-zinc-300'
              }`}
            >
              {name}
            </button>
          ))}
        </div>
      )}

      {/* 联系人卡片列表 */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        <AnimatePresence>
          {filteredFaces.map((face) => (
            <motion.div
              key={face.slug}
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="group bg-white rounded-3xl border border-zinc-100 overflow-hidden hover:border-zinc-300 hover:shadow-lg transition-all duration-300"
            >
              <Link href={`/faces${face.slug}`} className="block p-6">
                {/* 头像 */}
                <div className="w-20 h-20 bg-gradient-to-br from-zinc-100 to-zinc-50 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-zinc-100 group-hover:border-zinc-300 transition-colors">
                  <UserCircle size={40} className="text-zinc-300 group-hover:text-zinc-400 transition-colors" />
                </div>
                {/* 姓名 */}
                <h3 className="text-xl font-bold text-zinc-900 text-center mb-2 group-hover:text-zinc-600 transition-colors">
                  {face.title}
                </h3>
                {/* 描述 */}
                {face.description && (
                  <p className="text-zinc-400 text-sm text-center line-clamp-2 mb-3">
                    {face.description}
                  </p>
                )}
                {/* 标签 */}
                {face.tags.length > 0 && (
                  <div className="flex flex-wrap justify-center gap-1.5">
                    {face.tags.slice(0, 3).map((tag) => (
                      <span
                        key={tag}
                        className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 bg-zinc-50 px-2 py-0.5 rounded-full"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>
                )}
              </Link>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      {filteredFaces.length === 0 && (
        <div className="py-32 text-center bg-white rounded-[3rem] border border-zinc-100 shadow-sm">
          <div className="w-24 h-24 bg-zinc-50 rounded-full flex items-center justify-center mx-auto mb-6 text-zinc-300">
            <Users size={40} />
          </div>
          <h3 className="text-2xl font-black text-zinc-900 mb-2">暂无联系人</h3>
          <p className="text-zinc-400 font-medium">在 /faces 目录下添加 Markdown 文件即可创建联系人</p>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useRef, useEffect } from 'react';
import Link from 'next/link';
import { Button, Input, Form, message } from 'antd';
import { ChevronRight, Mail, ArrowLeft, CheckCircle } from 'lucide-react';
import { useI18n } from '@/hooks/use-i18n';
import AuthCard from '@/components/AuthCard';
import AuthLayout from '@/components/AuthLayout';

export default function ForgotPasswordPage() {
  const [loading, setLoading] = useState(false);
  const [emailSent, setEmailSent] = useState(false);
  const [sentEmail, setSentEmail] = useState('');
  const [form] = Form.useForm();
  const inputRef = useRef<any>(null);
  const { t } = useI18n();

  useEffect(() => { inputRef.current?.focus(); }, []);

  const handleSubmit = async (values: { email: string }) => {
    if (loading) return;
    setLoading(true);
    try {
      const res = await fetch('/api/auth/reset-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: values.email }),
      });
      const data = await res.json();
      if (res.ok || res.status === 201) {
        setSentEmail(values.email);
        setEmailSent(true);
        message.success(t('auth.resetLinkSent'));
      } else {
        message.error(data.error || t('auth.resetLinkFailed'));
      }
    } catch (error) {
      message.error(t('auth.resetLinkFailed'));
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = {
    padding: '14px 16px',
    height: 56,
    fontSize: 16,
    lineHeight: 1.6,
    borderRadius: 12,
  };

  if (emailSent) {
    return (
      <AuthLayout>
        <AuthCard
          footer={
            <div className="flex items-center justify-center gap-2 py-6">
              <Link href="/login">
                <Button icon={<ArrowLeft size={14} />} size="large">
                  {t('auth.backToLogin')}
                </Button>
              </Link>
            </div>
          }
          subtitle={t('auth.checkEmail')}
          title={t('auth.emailSent')}
        >
          <div className="flex items-center gap-4 p-6 rounded-xl" style={{ background: 'var(--ant-color-success-bg)', border: '1px solid var(--ant-color-success-border)' }}>
            <CheckCircle size={32} style={{ color: 'var(--ant-color-success)' }} />
            <div>
              <span className="text-base block mb-1">{t('auth.resetLinkSent')}</span>
              <span className="text-sm text-zinc-400">{sentEmail}</span>
            </div>
          </div>
          <Button size="large" block style={{ marginTop: 24 }} onClick={() => { setEmailSent(false); form.resetFields(); inputRef.current?.focus(); }}>
            {t('auth.resendEmail')}
          </Button>
        </AuthCard>
      </AuthLayout>
    );
  }

  return (
    <AuthLayout>
      <AuthCard
        footer={
          <div className="flex items-center justify-center gap-2 py-6">
            <Link href="/login">
              <Button icon={<ArrowLeft size={14} />} size="large">
                {t('auth.backToLogin')}
              </Button>
            </Link>
          </div>
        }
        subtitle={t('auth.forgotPasswordSubtitle')}
        title={t('auth.forgotPasswordTitle')}
      >
        <Form form={form} layout="vertical" onFinish={handleSubmit}>
          <Form.Item name="email" style={{ marginBottom: 0 }} rules={[
            { required: true, message: t('validation.required') },
            { type: 'email', message: t('validation.emailInvalid') },
          ]}>
            <Input
              placeholder={t('auth.inputEmailPlaceholder')}
              ref={inputRef}
              size="large"
              prefix={<Mail size={16} className="mx-2 text-zinc-400" />}
              style={inputStyle}
              suffix={
                <Button icon={<ChevronRight size={14} />} loading={loading} disabled={loading} title={t('auth.sendResetLink')} variant="filled" onClick={() => form.submit()} />
              }
            />
          </Form.Item>
        </Form>
      </AuthCard>
    </AuthLayout>
  );
}

'use client';

import React, { Suspense, useState, useEffect, useRef } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { Button, Input, Form, Divider, message } from 'antd';
import { ChevronRight, Lock, Mail } from 'lucide-react';
import { useAuth } from '@/hooks/use-auth';
import { useI18n } from '@/hooks/use-i18n';
import { ClerkAuthProvider } from '@/components/ClerkAuthProvider';
import { ClerkLoginSection } from '@/components/ClerkLoginSection';
import AuthCard from '@/components/AuthCard';
import AuthLayout from '@/components/AuthLayout';

/**
 * 登录表单 — 两步流程：先输入邮箱/用户名，再输入密码
 * 底部可选 Clerk 第三方登录（仅配置了 Clerk 环境变量时显示）
 */
function LoginForm() {
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<'email' | 'password'>('email');
  const [email, setEmail] = useState('');
  const router = useRouter();
  const searchParams = useSearchParams();
  const { login } = useAuth();
  const [form] = Form.useForm();
  const inputRef = useRef<any>(null);
  const { t } = useI18n();

  const callbackUrl = searchParams?.get('callbackUrl') || '/dashboard';
  const clerkAvailable = !!process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY;

  useEffect(() => {
    inputRef.current?.focus();
  }, [step]);

  const handleCheckUser = async (values: { login: string }) => {
    setLoading(true);
    try {
      setEmail(values.login);
      setStep('password');
    } catch {
      message.error(t('auth.loginFailed'));
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = async (values: { password: string }) => {
    setLoading(true);
    try {
      await login(email, values.password);
      router.push(callbackUrl);
    } catch {
      // useAuth 内部已处理错误提示
    } finally {
      setLoading(false);
    }
  };

  const handleBackToEmail = () => {
    setStep('email');
    setEmail('');
  };

  const inputStyle = {
    padding: '14px 16px',
    height: 56,
    fontSize: 16,
    lineHeight: 1.6,
    borderRadius: 12,
  };

  const clerkSection = clerkAvailable ? (
    <ClerkAuthProvider>
      <ClerkLoginSection />
    </ClerkAuthProvider>
  ) : null;

  const renderEmailStep = () => (
    <AuthCard
      footer={
        <div className="flex flex-col items-center gap-4 mt-4">
          <Link href="/forgot-password">
            <span className="text-sm text-zinc-400 cursor-pointer hover:text-zinc-600">
              {t('auth.forgotPassword')}
            </span>
          </Link>
          <div className="flex items-center justify-center gap-2">
            <span className="text-sm text-zinc-400">{t('auth.noAccount')}</span>
            <Link href="/register">
              <span className="text-sm font-medium text-zinc-900">{t('auth.registerNow')}</span>
            </Link>
          </div>
        </div>
      }
      subtitle={t('auth.loginSubtitle')}
      title={t('auth.welcomeBack')}
    >
      <Form form={form} layout="vertical" onFinish={handleCheckUser}>
        <Form.Item
          name="login"
          style={{ marginBottom: 0 }}
          rules={[{ required: true, message: t('auth.inputEmailOrUsername') }]}
        >
          <Input
            placeholder={t('auth.inputEmailOrUsername')}
            ref={inputRef}
            size="large"
            prefix={<Mail size={16} className="mx-2 text-zinc-400" />}
            style={inputStyle}
            suffix={
              <Button
                icon={<ChevronRight size={14} />}
                loading={loading}
                title={t('auth.nextStep')}
                variant={'filled'}
                onClick={() => form.submit()}
              />
            }
          />
        </Form.Item>
      </Form>
      {clerkSection}
    </AuthCard>
  );

  const renderPasswordStep = () => (
    <AuthCard
      footer={
        <div className="flex flex-col gap-4">
          <Link href="/forgot-password">
            <span className="text-sm cursor-pointer" style={{ color: 'var(--ant-color-primary)' }}>
              {t('auth.forgotPassword')}
            </span>
          </Link>
          <Button
            icon={<ChevronRight size={14} className="rotate-180" />}
            size={'large'}
            onClick={handleBackToEmail}
          >
            {t('common.back')}
          </Button>
        </div>
      }
      subtitle={t('auth.inputPasswordToLogin')}
      title={t('auth.welcomeBack')}
    >
      <span className="text-lg text-zinc-900">{email}</span>
      <Form form={form} layout="vertical" style={{ marginTop: 16 }} onFinish={handleLogin}>
        <Form.Item
          name="password"
          rules={[{ required: true, message: t('auth.inputPassword') }]}
          style={{ marginBottom: 0 }}
        >
          <Input.Password
            placeholder={t('auth.inputPassword')}
            ref={inputRef}
            size="large"
            prefix={<Lock size={16} className="mx-2 text-zinc-400" />}
            style={inputStyle}
            suffix={
              <Button
                icon={<ChevronRight size={14} />}
                loading={loading}
                style={{ color: 'var(--ant-color-primary)' }}
                title={t('auth.login')}
                variant={'filled'}
                onClick={() => form.submit()}
              />
            }
          />
        </Form.Item>
      </Form>
      {clerkSection}
    </AuthCard>
  );

  return (
    <AuthLayout>
      {step === 'email' ? renderEmailStep() : renderPasswordStep()}
    </AuthLayout>
  );
}

export default function LoginPage() {
  return (
    <Suspense fallback={<div>加载中...</div>}>
      <LoginForm />
    </Suspense>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { Button, Input, Form, notification, message, Select, Spin } from 'antd';
import { User, Lock, Mail, UserX } from 'lucide-react';
import AuthCard from '@/components/AuthCard';
import AuthLayout from '@/components/AuthLayout';

interface UserGroup {
  id: string;
  name: string;
  description: string;
  isDefault?: boolean;
}

export default function RegisterPage() {
  const [loading, setLoading] = useState(false);
  const [groups, setGroups] = useState<UserGroup[]>([]);
  const [registrationOpen, setRegistrationOpen] = useState<boolean | null>(null);
  const router = useRouter();
  const [form] = Form.useForm();

  useEffect(() => {
    // 检查是否允许注册
    fetch('/api/config')
      .then(res => res.json())
      .then(data => {
        setRegistrationOpen(data.auth?.allowRegistration !== false);
      })
      .catch(() => {
        setRegistrationOpen(true); // 获取失败时默认允许
      });

    const fetchGroups = async () => {
      try {
        const res = await fetch('/api/user-groups');
        if (res.ok) {
          const data = await res.json();
          setGroups(data.filter((g: UserGroup) => g.id !== 'sudo' && g.id !== 'admin'));
        }
      } catch (error) {
        console.error('获取用户组失败:', error);
      }
    };
    fetchGroups();
  }, []);

  const onFinish = async (values: any) => {
    setLoading(true);
    try {
      if (values.password !== values.confirmPassword) {
        throw new Error('两次输入的密码不一致');
      }
      const res = await fetch('/api/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email: values.email,
          username: values.username,
          password: values.password,
          name: values.name || values.email.split('@')[0],
          userGroup: values.userGroup || 'default',
        }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        const roleMsg = data.user?.role === 'sudo' ? '您是首个注册用户，已获得管理员权限！' : '账号已创建，请前往登录';
        notification.success({ message: '注册成功', description: roleMsg, placement: 'topRight', duration: 5 });
        router.push('/login');
      } else if (data.errorKey === 'registration_closed') {
        setRegistrationOpen(false);
      } else {
        throw new Error(data.error || data.message || '注册失败');
      }
    } catch (err: any) {
      console.error('注册失败:', err);
      message.error(err.message || '注册失败');
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = {
    padding: '14px 16px',
    height: 56,
    fontSize: 16,
    lineHeight: 1.6,
    borderRadius: 12,
  };

  // 正在加载配置
  if (registrationOpen === null) {
    return (
      <AuthLayout>
        <div className="flex items-center justify-center py-20">
          <Spin size="large" />
        </div>
      </AuthLayout>
    );
  }

  // 注册已关闭
  if (!registrationOpen) {
    return (
      <AuthLayout>
        <AuthCard
          footer={
            <div className="flex items-center justify-center gap-2 py-6">
              <span className="text-sm text-zinc-400">已有账号？</span>
              <Link href="/login">
                <span className="text-sm font-medium text-zinc-900">立即登录</span>
              </Link>
            </div>
          }
          subtitle="管理员已关闭新用户注册"
          title="注册已关闭"
        >
          <div className="flex flex-col items-center py-8 text-center">
            <div className="w-16 h-16 bg-zinc-100 rounded-2xl flex items-center justify-center mb-4">
              <UserX size={28} className="text-zinc-400" />
            </div>
            <p className="text-zinc-400 text-sm mb-6">
              当前站点不接受新用户注册。如有疑问，请联系管理员。
            </p>
            <Link href="/login">
              <Button type="primary" size="large" className="bg-zinc-900 rounded-xl h-12 px-8">
                返回登录
              </Button>
            </Link>
          </div>
        </AuthCard>
      </AuthLayout>
    );
  }

  // 注册开放
  return (
    <AuthLayout>
      <AuthCard
        footer={
          <div className="flex items-center justify-center gap-2 py-6">
            <span className="text-sm text-zinc-400">已有账号？</span>
            <Link href="/login">
              <span className="text-sm font-medium text-zinc-900">立即登录</span>
            </Link>
          </div>
        }
        subtitle="加入 Originium Kernel"
        title="创建账号"
      >
        <Form form={form} layout="vertical" onFinish={onFinish}>
          <Form.Item name="email" style={{ marginBottom: 16 }} rules={[
            { required: true, message: '请输入电子邮箱' },
            { type: 'email', message: '请输入有效的电子邮箱地址' },
          ]}>
            <Input placeholder="your@email.com" size="large" prefix={<Mail size={16} className="mx-2 text-zinc-400" />} style={inputStyle} />
          </Form.Item>
          <Form.Item name="username" style={{ marginBottom: 16 }} rules={[
            { required: true, message: '请输入用户名' },
            { pattern: /^[a-zA-Z0-9_]{3,20}$/, message: '用户名只能包含字母、数字和下划线，3-20个字符' },
          ]}>
            <Input placeholder="用户名（用于登录）" size="large" prefix={<User size={16} className="mx-2 text-zinc-400" />} style={inputStyle} />
          </Form.Item>
          <Form.Item name="name" style={{ marginBottom: 16 }} rules={[
            { required: true, message: '请输入昵称' },
            { min: 2, message: '昵称至少 2 个字符' },
          ]}>
            <Input placeholder="您的昵称" size="large" prefix={<User size={16} className="mx-2 text-zinc-400" />} style={inputStyle} />
          </Form.Item>
          <Form.Item name="password" style={{ marginBottom: 16 }} rules={[
            { required: true, message: '请输入密码' },
            { min: 6, message: '密码至少 6 个字符' },
          ]}>
            <Input.Password placeholder="至少 6 个字符" size="large" prefix={<Lock size={16} className="mx-2 text-zinc-400" />} style={inputStyle} />
          </Form.Item>
          {groups.length > 0 && (
            <Form.Item name="userGroup" style={{ marginBottom: 16 }} initialValue="default">
              <Select size="large" placeholder="选择用户组" style={{ height: 56 }} options={groups.map(g => ({ label: g.name, value: g.id }))} />
            </Form.Item>
          )}
          <Form.Item name="confirmPassword" style={{ marginBottom: 0 }} dependencies={['password']} rules={[
            { required: true, message: '请确认您的密码' },
            ({ getFieldValue }) => ({
              validator(_, value) {
                if (!value || getFieldValue('password') === value) return Promise.resolve();
                return Promise.reject(new Error('两次输入的密码不一致'));
              },
            }),
          ]}>
            <Input.Password placeholder="再次输入密码" size="large" prefix={<Lock size={16} className="mx-2 text-zinc-400" />} style={inputStyle} />
          </Form.Item>
          <Form.Item style={{ marginTop: 32, marginBottom: 0 }}>
            <Button block htmlType="submit" loading={loading} size="large" type="primary" style={{ height: 48, borderRadius: 8, fontSize: 16 }}>
              立即注册
            </Button>
          </Form.Item>
        </Form>
      </AuthCard>
    </AuthLayout>
  );
}

'use client';

import React, { useState, useRef, useEffect, Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { Button, Input, Form, message } from 'antd';
import { ChevronRight, Lock, ArrowLeft, CheckCircle } from 'lucide-react';
import { useI18n } from '@/hooks/use-i18n';
import AuthCard from '@/components/AuthCard';
import AuthLayout from '@/components/AuthLayout';

function ResetPasswordForm() {
  const [loading, setLoading] = useState(false);
  const [resetSuccess, setResetSuccess] = useState(false);
  const [form] = Form.useForm();
  const router = useRouter();
  const searchParams = useSearchParams();
  const token = searchParams?.get('token');
  const inputRef = useRef<any>(null);
  const { t } = useI18n();

  useEffect(() => {
    if (!token) {
      message.error(t('auth.invalidToken'));
      router.push('/login');
    }
    inputRef.current?.focus();
  }, [token, router, t]);

  const handleSubmit = async (values: { password: string; confirmPassword: string }) => {
    if (loading || !token) return;
    if (values.password !== values.confirmPassword) {
      message.error(t('validation.passwordMismatch'));
      return;
    }
    if (values.password.length < 6) {
      message.error(t('validation.passwordTooShort'));
      return;
    }
    setLoading(true);
    try {
      const res = await fetch('/api/auth/reset-password', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token, password: values.password }),
      });
      const data = await res.json();
      if (res.ok || res.status === 201) {
        setResetSuccess(true);
        message.success(t('auth.resetSuccess'));
      } else {
        message.error(data.error || t('auth.resetFailed'));
      }
    } catch (error) {
      message.error(t('auth.resetFailed'));
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = {
    padding: '14px 16px',
    height: 56,
    fontSize: 16,
    lineHeight: 1.6,
    borderRadius: 12,
  };

  if (resetSuccess) {
    return (
      <AuthLayout>
        <AuthCard
          footer={
            <div className="flex items-center justify-center gap-2 py-6">
              <Link href="/login">
                <Button icon={<ArrowLeft size={14} />} size="large">
                  {t('auth.backToLogin')}
                </Button>
              </Link>
            </div>
          }
          subtitle={t('auth.loginSubtitle')}
          title={t('auth.resetSuccess')}
        >
          <div className="flex items-center gap-4 p-6 rounded-xl" style={{ background: 'var(--ant-color-success-bg)', border: '1px solid var(--ant-color-success-border)' }}>
            <CheckCircle size={32} style={{ color: 'var(--ant-color-success)' }} />
            <span className="text-base">{t('auth.resetSuccess')}</span>
          </div>
          <Link href="/login">
            <Button type="primary" size="large" block style={{ marginTop: 24 }}>
              {t('auth.login')}
            </Button>
          </Link>
        </AuthCard>
      </AuthLayout>
    );
  }

  return (
    <AuthLayout>
      <AuthCard
        footer={
          <div className="flex items-center justify-center gap-2 py-6">
            <Link href="/login">
              <Button icon={<ArrowLeft size={14} />} size="large">
                {t('auth.backToLogin')}
              </Button>
            </Link>
          </div>
        }
        subtitle={t('auth.resetPasswordSubtitle')}
        title={t('auth.resetPasswordTitle')}
      >
        <Form form={form} layout="vertical" onFinish={handleSubmit}>
          <Form.Item name="password" style={{ marginBottom: 16 }} rules={[
            { required: true, message: t('validation.required') },
            { min: 6, message: t('validation.passwordTooShort') },
          ]}>
            <Input.Password placeholder={t('auth.newPassword')} ref={inputRef} size="large" prefix={<Lock size={16} className="mx-2 text-zinc-400" />} style={inputStyle} />
          </Form.Item>
          <Form.Item name="confirmPassword" style={{ marginBottom: 0 }} rules={[
            { required: true, message: t('validation.required') },
            ({ getFieldValue }) => ({
              validator(_, value) {
                if (!value || getFieldValue('password') === value) return Promise.resolve();
                return Promise.reject(new Error(t('validation.passwordMismatch')));
              },
            }),
          ]}>
            <Input.Password
              placeholder={t('auth.confirmNewPassword')}
              size="large"
              prefix={<Lock size={16} className="mx-2 text-zinc-400" />}
              style={inputStyle}
              suffix={
                <Button icon={<ChevronRight size={14} />} loading={loading} disabled={loading} title={t('auth.resetPassword')} variant="filled" onClick={() => form.submit()} />
              }
            />
          </Form.Item>
        </Form>
      </AuthCard>
    </AuthLayout>
  );
}

function ResetPasswordLoading() {
  const { t } = useI18n();
  return <div>{t('common.loading')}</div>;
}

export default function ResetPasswordPage() {
  return (
    <Suspense fallback={<ResetPasswordLoading />}>
      <ResetPasswordForm />
    </Suspense>
  );
}

