      <nav className="flex-1 overflow-y-auto px-3 py-4 space-y-5">
        {Object.entries(grouped).map(([group, groupItems]) => {
          const isCollapsed = collapsedGroups[group];
          const isAdminGroup = group === 'admin';

          return (
            <div key={group}>
