const fs = require('fs');
const cp = require('child_process');

// run eslint and capture json output
try {
  cp.execSync('npx eslint . -f json > lint-results.json 2>/dev/null');
} catch (e) {
  // it throws if there are errors, which is expected
}

const raw = fs.readFileSync('lint-results.json', 'utf-8');
const results = JSON.parse(raw);

results.forEach(fileResult => {
  if (fileResult.errorCount === 0 && fileResult.warningCount === 0) return;
  const filePath = fileResult.filePath;
  let lines = fs.readFileSync(filePath, 'utf-8').split('\n');

  // Sort messages descending by line number and column, so prepending/editing doesn't shift later fixes
  const messages = fileResult.messages.sort((a, b) => {
    if (a.line !== b.line) return b.line - a.line;
    return b.column - a.column;
  });

  messages.forEach(msg => {
    const lineIndex = msg.line - 1;
    const colIndex = msg.column - 1;

