import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)

    const initialValue = window.innerWidth < MOBILE_BREAKPOINT;
    if (isMobile !== initialValue) {
      setIsMobile(initialValue);
    }

    return () => mql.removeEventListener("change", onChange)
  }, [isMobile])

  return !!isMobile
}

import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Authentication logic for Originium Kernel (Serverless/Edge)
 */

const SECRET = new TextEncoder().encode(
  process.env.AUTH_SECRET || 'fallback-secret-at-least-32-chars-long'
);

export interface SessionPayload {
  uid: string;
  email: string;
  role: 'user' | 'admin' | 'sudo';
  userGroup?: string;
}

/**
 * Generate UID (WID)
 */
export function generateUID(): string {
  const timestamp = Date.now().toString(36).toUpperCase();
  const randomStr = Math.random().toString(36).substring(2, 7).toUpperCase();
  return `UID-${timestamp}-${randomStr}`;
}

/**
 * Create a new session JWT
 */
export async function createSession(payload: SessionPayload) {
  const expires = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000); // 7 days
  const session = await new SignJWT({ ...payload })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('7d')
    .sign(SECRET);

  (await cookies()).set('session', session, {
    expires,
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/',
  });

  return session;
}

/**
 * Get current session from cookies
 */
export async function getSession(): Promise<SessionPayload | null> {
  const session = (await cookies()).get('session')?.value;
  if (!session) return null;

  try {
    const { payload } = await jwtVerify(session, SECRET, {
      algorithms: ['HS256'],
    });
    return payload as unknown as SessionPayload;
  } catch (err) {
    return null;
  }
}

/**
 * Delete current session
 */
export async function deleteSession() {
  (await cookies()).delete('session');
}

/**
 * Middleware helper to protect routes
 */
export async function verifyAuth(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return { authenticated: false, session: null };
  }
  return { authenticated: true, session };
}

/**
 * Permission Middleware - Require Authentication
 */
export async function requireAuth(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: 'Authentication required' }, { status: 401 });
  }
  return session;
}

/**
 * Permission Middleware - Require Admin or Sudo role
 */
export async function requireAdmin(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: 'Authentication required' }, { status: 401 });
  }
  if (session.role !== 'admin' && session.role !== 'sudo') {
    return NextResponse.json({ error: 'Admin access required' }, { status: 403 });
  }
  return session;
}

/**
 * Permission Middleware - Require Sudo role only
 */
export async function requireSudo(req: NextRequest) {
  const session = await getSession();
  if (!session) {
    return NextResponse.json({ error: 'Authentication required' }, { status: 401 });
  }
  if (session.role !== 'sudo') {
    return NextResponse.json({ error: 'Sudo access required' }, { status: 403 });
  }
  return session;
}

/**
 * Check if user has specific role
 */
export function hasRole(session: SessionPayload | null, roles: Array<'user' | 'admin' | 'sudo'>): boolean {
  if (!session) return false;
  return roles.includes(session.role);
}

import { Octokit } from 'octokit';
import yaml from 'js-yaml';

/**
 * GitHub 集成 — 文件推送/读取/删除
 */

interface GithubSyncParams {
  repo: string;
  token: string;
  path: string;
  content: string;
  message: string;
}

/** 从 GitHub 获取文件内容 */
export async function getFileFromGithub(repo: string, token: string, path: string) {
  const [owner, repoName] = repo.split('/');
  const octokit = new Octokit({ auth: token });

  try {
    const { data } = await octokit.rest.repos.getContent({
      owner,
      repo: repoName,
      path,
    });

    if ('content' in data) {
      const content = Buffer.from(data.content, 'base64').toString('utf-8');
      return { content, sha: data.sha };
    }
    return null;
  } catch (error: any) {
    if (error.status === 404) return null;
    throw error;
  }
}

/** 创建或更新 GitHub 上的文件 */
export async function updateFileInGithub({ repo, token, path, content, message }: GithubSyncParams) {
  const [owner, repoName] = repo.split('/');
  const octokit = new Octokit({ auth: token });
  const existingFile = await getFileFromGithub(repo, token, path);

  return await octokit.rest.repos.createOrUpdateFileContents({
    owner,
    repo: repoName,
    path,
    message,
    content: Buffer.from(content).toString('base64'),
    sha: existingFile?.sha,
  });
}

/** 删除 GitHub 上的文件 */
export async function deleteFileFromGithub(repo: string, token: string, path: string) {
  const [owner, repoName] = repo.split('/');
  const octokit = new Octokit({ auth: token });
  const existingFile = await getFileFromGithub(repo, token, path);
  if (!existingFile) return null;

  return await octokit.rest.repos.deleteFile({
    owner,
    repo: repoName,
    path,
    message: `delete: remove ${path}`,
    sha: existingFile.sha,
  });
}

/**
 * 将帖子以 Markdown 格式推送到 GitHub posts/ 目录
 * 文件路径格式：posts/{category}/{slug}.md
 */
export async function syncPostToGithub(
  repo: string,
  token: string,
  post: {
    slug: string;
    title: string;
    content: string;
    author?: string;
    tags?: string[];
    cover?: string;
    date?: string;
    description?: string;
  },
) {
  const frontMatter: Record<string, any> = {
    title: post.title,
    author: post.author || 'Anonymous',
    date: post.date || new Date().toISOString(),
    tags: post.tags || [],
  };
  if (post.cover) frontMatter.cover = post.cover;
  if (post.description) frontMatter.description = post.description;

  const fileContent = `---\n${yaml.dump(frontMatter)}---\n\n${post.content}`;
  const filePath = `posts${post.slug}.md`;

  return await updateFileInGithub({
    repo,
    token,
    path: filePath,
    content: fileContent,
    message: `feat: publish post "${post.title}"`,
  });
}

/**
 * 从 GitHub posts/ 目录删除帖子
 */
export async function deletePostFromGithub(repo: string, token: string, slug: string) {
  const filePath = `posts${slug}.md`;
  return await deleteFileFromGithub(repo, token, filePath);
}

/**
 * 同步配置到 GitHub（YAML + JSON 双格式）
 */
export async function syncConfigToGithub(repo: string, token: string, config: any) {
  const yamlContent = yaml.dump(config);
  const jsonContent = JSON.stringify(config, null, 2);

  await updateFileInGithub({
    repo,
    token,
    path: 'config.yaml',
    content: yamlContent,
    message: 'chore: update config.yaml',
  });
  await updateFileInGithub({
    repo,
    token,
    path: 'config.json',
    content: jsonContent,
    message: 'chore: update config.json',
  });
}

import matter from 'gray-matter';

/**
 * Markdown + Front Matter Parser for Originium Kernel
 */

export interface FrontMatter {
  title: string;
  author?: string;
  tags?: string[];
  cover?: string;
  date?: string;
  [key: string]: any;
}

export interface ParsedMarkdown {
  content: string;
  frontMatter: FrontMatter;
}

/**
 * Parse Markdown with Front Matter
 */
export function parseMarkdown(markdown: string): ParsedMarkdown {
  try {
    const { data, content } = matter(markdown);
    return {
      content,
      frontMatter: data as FrontMatter,
    };
  } catch (error) {
    // If parsing fails, return full content without front matter
    return {
      content: markdown,
      frontMatter: { title: 'Untitled' },
    };
  }
}

/**
 * Extract front matter only (for indexing)
 */
export function extractFrontMatter(markdown: string): FrontMatter {
  const { frontMatter } = parseMarkdown(markdown);
  return frontMatter;
}

/**
 * Generate Markdown with Front Matter
 */
export function generateMarkdown(frontMatter: FrontMatter, content: string): string {
  return matter.stringify(content, frontMatter);
}

/**
 * Format date for display
 */
export function formatDate(dateString?: string): string {
  if (!dateString) return '';
  const date = new Date(dateString);
  return date.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });
}

/**
 * Extract tags from front matter
 */
export function extractTags(markdown: string): string[] {
  const { frontMatter } = parseMarkdown(markdown);
  if (!frontMatter.tags) return [];
  return Array.isArray(frontMatter.tags) ? frontMatter.tags : [frontMatter.tags];
}

import fs from 'fs';
import path from 'path';
import matter from 'gray-matter';

/** 工单模板字段定义 */
export interface TicketField {
  name: string;
  label: string;
  type: 'input' | 'textarea' | 'dropdown' | 'checkboxes';
  options?: string[];
  required: boolean;
}

/** 工单模板 */
export interface TicketTemplate {
  slug: string;
  name: string;
  description: string;
  title: string;
  labels: string[];
  assignees: string[];
  fields: TicketField[];
  body: string; // 模板正文（包含 {{field}} 占位符）
}

const TICKETS_DIR = path.join(process.cwd(), 'tickets');

/**
 * 获取所有工单模板（构建时调用）
 */
export function getTicketTemplates(): TicketTemplate[] {
  if (!fs.existsSync(TICKETS_DIR)) return [];

  const files = fs.readdirSync(TICKETS_DIR).filter(f => f.endsWith('.md'));
  const templates: TicketTemplate[] = [];

  for (const file of files) {
    const filePath = path.join(TICKETS_DIR, file);
    const raw = fs.readFileSync(filePath, 'utf-8');
    const { data, content } = matter(raw);

    // 解析 fields
    const fields: TicketField[] = (data.fields || []).map((f: any) => ({
      name: f.name,
      label: f.label || f.name,
      type: f.type || 'input',
      options: f.options || [],
      required: f.required !== false,
    }));

    templates.push({
      slug: '/' + file.replace(/\.md$/, ''),
      name: data.name || path.basename(file, '.md'),
      description: data.description || '',
      title: data.title || '',
      labels: data.labels || [],
      assignees: data.assignees || [],
      fields,
      body: content,
    });
  }

  return templates;
}

/**
 * 根据 slug 获取单个工单模板
 */
export function getTicketTemplate(slug: string): TicketTemplate | null {
  const templates = getTicketTemplates();
  return templates.find(t => t.slug === slug) || null;
}

/**
 * 将表单数据填充到模板中，生成最终 markdown 内容
 */
export function renderTicketBody(template: TicketTemplate, formData: Record<string, string>): string {
  let body = template.body;

  // 替换 {{fieldName}} 占位符
  for (const [key, value] of Object.entries(formData)) {
    body = body.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value || '');
  }

  return body;
}

